// G-TELP Level 2 기출 유형 문제 (80문항×5회)
const pastExams = [{"round":1,"title":"제1회 기출 유형","analysis":{"summary":"현재완료·과거완료 집중, 가정법 과거/과거완료 혼합, 준동사 to부정사·동명사 구분, 관계사 who/whose, 조동사 must/should. 청취 Part1 짧은 대화 7문항·Part4 강의형 7문항, 독해 3지문 28문항.","tips":["현재완료: since/for/already/yet/ever 키워드","가정법 if절 시제 → 귀결절 형태 결정","준동사: suggest/recommend/avoid = 동명사, plan/decide/want = to부정사"]},"qs":[{"type":"현재완료","q":"The unit _____ on standby since 0600.","opts":["is","was","has been","had been"],"ans":2,"exp":"since+시점 → 현재완료(has been)","section":"문법"},{"type":"과거완료","q":"The evacuation _____ completed before the structure collapsed.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거(collapsed) → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"가정법 과거","q":"If the equipment _____ in better condition, the task would be easier.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"가정법 과거완료","q":"If the team _____ the warning, the firefighter would not have been injured.","opts":["heeded","heeds","had heeded","has heeded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., would have p.p.","section":"문법"},{"type":"준동사-동명사","q":"The chief recommended _____ all rooftop access points before committing crews.","opts":["to assess","assess","assessing","assessed"],"ans":2,"exp":"recommend+동명사(V-ing)","section":"문법"},{"type":"준동사-to부정사","q":"The department agreed _____ the new accountability system by January.","opts":["implement","implementing","to implement","implemented"],"ans":2,"exp":"agree+to부정사","section":"문법"},{"type":"관계사-who","q":"The medic _____ treated the burn victims received a commendation.","opts":["who","which","whose","whom"],"ans":0,"exp":"사람 선행사+주어 역할 → who","section":"문법"},{"type":"관계사-whose","q":"The officer _____ unit responded first was praised for the fastest deployment.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"조동사-must","q":"The radio must _____ malfunctioned — no transmissions were received.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측","section":"문법"},{"type":"조동사-should","q":"The crew should _____ performed a 360-degree walkthrough before entry.","opts":["have","had","be","has"],"ans":0,"exp":"should have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"수동태","q":"The incident report _____ finalized before the press briefing.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"미래완료","q":"By next Tuesday, the department _____ its centennial celebrations.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by+미래시점 → 미래완료(will have p.p.)","section":"문법"},{"type":"분사구문","q":"The alarm _____ at midnight, all off-duty personnel were immediately recalled.","opts":["sounding","having sounded","sounded","to sound"],"ans":1,"exp":"Having p.p. = 경보가 울린 후 → 수동 분사구문","section":"문법"},{"type":"분사구문","q":"_____ all exits, the safety team confirmed the building was clear.","opts":["Checking","Having checked","To check","Checked"],"ans":1,"exp":"분사구문: Having p.p. = 주절보다 이전에 완료된 동작","section":"문법"},{"type":"가정법-wish","q":"The firefighter wishes she _____ more time to practice the drill.","opts":["has","had","would have","will have"],"ans":1,"exp":"wish+가정법 과거: wish+주어+had → 현재 사실 반대","section":"문법"},{"type":"도치","q":"Only then _____ the true extent of the damage.","opts":["they realized","did they realize","they did realize","realized they"],"ans":1,"exp":"Only+부사 문두 → 조동사+주어 도치","section":"문법"},{"type":"준동사-사역동사","q":"The chief had the recruits _____ the drill twice.","opts":["repeat","to repeat","repeating","repeated"],"ans":0,"exp":"사역동사(have)+목적어+동사원형","section":"문법"},{"type":"부정사 구문","q":"The regulation requires all units _____ before entering IDLH environments.","opts":["check","checking","to check","checked"],"ans":2,"exp":"require+목적어+to부정사: requires A to V","section":"문법"},{"type":"가정법-wish","q":"I wish the department _____ adopted the new protocol earlier.","opts":["has","had","would have","will have"],"ans":1,"exp":"wish+가정법 과거완료: wish+주어+had p.p. → 과거 사실 반대","section":"문법"},{"type":"강조구문","q":"It was the outdated equipment _____ caused the malfunction.","opts":["which","that","who","what"],"ans":1,"exp":"강조구문(It is ... that): It was X that Y → that 고정","section":"문법"},{"type":"관계부사","q":"The protocol explains the reason _____ all aerial operations were suspended.","opts":["which","that","why","for which"],"ans":2,"exp":"reason+why = 이유 관계부사(= for which)","section":"문법"},{"type":"준동사-지각동사","q":"The supervisor heard the team _____ the evacuation alarm.","opts":["to activate","activating","activated","activation"],"ans":1,"exp":"지각동사(hear)+목적어+V-ing(진행 중인 동작)","section":"문법"},{"type":"복합 시제","q":"By the time you read this report, the investigation _____ for a week.","opts":["will run","will be running","will have been running","runs"],"ans":2,"exp":"by the time+현재 → 미래완료진행(will have been V-ing)","section":"문법"},{"type":"복합 관계사","q":"The commander approved _____ the safety officer recommended.","opts":["that","which","what","who"],"ans":2,"exp":"선행사 없는 명사절 목적어 → what(~하는 것을)","section":"문법"},{"type":"간접의문문","q":"The chief asked _____ the new recruits had passed their fitness test.","opts":["that whether","if","whether that","that"],"ans":1,"exp":"간접의문문: asked if/whether+주어+동사","section":"문법"},{"type":"간접의문문","q":"Could you tell me _____ the drill starts?","opts":["when does","when","what time does","that when"],"ans":1,"exp":"간접의문문: 의문사+주어+동사(정상 어순)","section":"문법"},{"part":1,"q":"[Part 1] \"Are there any exposures we need to protect?\"\n\"The east wall is about fifteen feet from an occupied residential building.\"\n\nQ: 노출 위험 건물의 위치는?","opts":["서쪽 15피트","동쪽 15피트","북쪽 20피트","남쪽 10피트"],"ans":1,"exp":"'east wall ... fifteen feet from residential building'","section":"청취"},{"part":1,"q":"[Part 1] \"Did the building owner provide access to the utility room?\"\n\"Eventually — took about twenty minutes of negotiation.\"\n\nQ: 다용도실 접근은?","opts":["즉시 허용","약 20분 협상 후 허용","거부됨","경찰이 강제 진입"],"ans":1,"exp":"'took about twenty minutes of negotiation'","section":"청취"},{"part":1,"q":"[Part 1] \"Is the water supply adequate for a prolonged operation?\"\n\"We've got two hydrants on Oak and Main — should be sufficient.\"\n\nQ: 사용 가능한 소화전 수는?","opts":["1개","2개","3개","4개"],"ans":1,"exp":"'two hydrants on Oak and Main'","section":"청취"},{"part":1,"q":"[Part 1] \"How many civilians were displaced by the fire?\"\n\"Forty-three. The Red Cross has set up a shelter at the community center.\"\n\nQ: 이재민 수용 장소는?","opts":["학교","소방서","지역 센터","호텔"],"ans":2,"exp":"'Red Cross ... shelter at the community center'","section":"청취"},{"part":1,"q":"[Part 1] \"Is the incident commander still on scene?\"\n\"He handed off to Battalion Chief Park about an hour ago.\"\n\nQ: 현재 사고지휘관은?","opts":["원래 지휘관","Park 대대장","부서장","훈련 지휘관"],"ans":1,"exp":"'handed off to Battalion Chief Park'","section":"청취"},{"part":1,"q":"[Part 1] \"Has the gas been shut off?\"\n\"The utility company confirmed it was isolated at 0312.\"\n\nQ: 가스 차단 시간은?","opts":["0212","0312","0412","0512"],"ans":1,"exp":"'isolated at 0312'","section":"청취"},{"part":1,"q":"[Part 1] \"Did all personnel make it out of the collapse zone?\"\n\"All accounted for — PAR was clear.\"\n\nQ: 붕괴 구역 인원 현황은?","opts":["1명 행방불명","전원 확인 완료","2명 부상","PAR 미실시"],"ans":1,"exp":"'All accounted for — PAR was clear'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The post-incident analysis showed three critical decision points where the outcome could have been different.\"\n\"Which ones?\"\n\"Entry timing, ventilation coordination, and RIT positioning. If any one of those had gone differently, we might have had a mayday.\"\n\nQ: 분석에서 밝혀진 결정적 실수 수는?","opts":["1가지","2가지","3가지","4가지"],"ans":2,"exp":"'three critical decision points'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The thermal camera flagged a hot spot on the east wall during overhaul.\"\n\"Did the crew investigate it?\"\n\"Yes — they opened up about four feet of wall and found smoldering insulation. It was extinguished, but it could have rekindled overnight.\"\n\nQ: 동쪽 벽에서 발견된 것은?","opts":["가스관 손상","훈소하는 단열재","전기 화재 흔적","구조적 손상"],"ans":1,"exp":"'smoldering insulation'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"Good catch. Make sure overhaul protocols include mandatory thermal imaging of adjacent walls going forward.\"\n\"Already drafting the SOG update. I'll have it ready by next shift.\"\n\nQ: SOG 업데이트 완료 예정 시점은?","opts":["오늘 중","다음 교대 전","다음 주","한 달 이내"],"ans":1,"exp":"'ready by next shift'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"What's the main takeaway from this incident?\"\n\"Coordination between ventilation and attack teams needs to be tighter. We'll add that to the drill curriculum.\"\n\nQ: 주요 개선 사항은?","opts":["RIT 배치 변경","환기-진압 팀 조율 강화","진입 시점 교정","MAYDAY 절차 수정"],"ans":1,"exp":"'Coordination between ventilation and attack teams needs to be tighter'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The community is demanding a public explanation for the response delay.\"\n\"I understand. We need to be transparent. Let's schedule a press conference and walk them through the timeline.\"\n\"Should we involve legal counsel?\"\n\"Yes — standard procedure for any incident that draws this level of scrutiny.\"\n\nQ: 대응 지연에 대한 결정된 조치는?","opts":["언론 보도 차단","법적 대응 거부","기자회견 개최 및 타임라인 공개","관계자 즉시 징계"],"ans":2,"exp":"'schedule a press conference and walk them through the timeline'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"When should we hold the press conference?\"\n\"Let's aim for Thursday — that gives us two days to compile the full timeline and coordinate with the mayor's office.\"\n\nQ: 기자회견 예정일은?","opts":["화요일","수요일","목요일","금요일"],"ans":2,"exp":"'aim for Thursday'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Effective immediately, all incident commanders must submit a written size-up report within 30 minutes of arrival at any working structure fire. The report must include: life safety status, fire conditions, building construction type, and resource needs. Forms are available in the command vehicle.\"\n\nQ: 30분 이내 보고서에 포함해야 할 항목이 아닌 것은?","opts":["인명 안전 현황","화재 조건","건물 구조 유형","화재 원인 추정"],"ans":3,"exp":"화재 원인 추정은 언급된 4개 항목에 없음","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"The new Personnel Accountability System goes live on the first of next month. Every firefighter will be issued a new accountability tag embedded with an RFID chip. These replace the old dog-tag system. Failure to carry your tag while on duty will result in a written warning on first offense, and suspension on the second.\"\n\nQ: 태그 미소지 시 두 번째 위반 처벌은?","opts":["구두 경고","서면 경고","정직","해임"],"ans":2,"exp":"'suspension on the second'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Tonight's scene involves a suspected natural gas leak in a residential neighborhood. Evacuate a two-block radius. No motorized vehicles, open flames, or electrical operation within that zone. Once the utility company confirms isolation, ventilate the affected structures before allowing any re-entry.\"\n\nQ: 가스 차단 확인 후 재진입 전 해야 할 것은?","opts":["구조물 사진 촬영","인근 건물 수색","영향받은 구조물 환기","전기 공급 복구"],"ans":2,"exp":"'ventilate the affected structures before allowing any re-entry'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"A reminder that all annual SCBA fit tests must be completed before the end of the quarter. If you have not yet scheduled yours, contact the equipment coordinator immediately. Personnel who fail to complete the test will be placed on restricted duty until compliance is achieved.\"\n\nQ: 적합성 시험 미완료 시 결과는?","opts":["급여 삭감","징계 처분","제한 근무 배치","즉시 휴직"],"ans":2,"exp":"'placed on restricted duty until compliance is achieved'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"The department will be conducting a multi-agency disaster drill on the 18th. Participating agencies include fire, EMS, law enforcement, and public works. All personnel should be in uniform and report to the staging area at 0700. Observers from city hall will be present, so professionalism is expected.\"\n\nQ: 훈련에 참여하지 않는 기관은?","opts":["소방","의료","법 집행","공중 보건"],"ans":3,"exp":"public works(공공 작업)가 있지만 공중 보건(public health)은 언급되지 않음","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Following last month's near-miss incident, all engine companies will participate in a mandatory hose load refresher. The training will be conducted in three sessions this week: Tuesday, Wednesday, and Friday. All company officers must sign attendance sheets and submit them to training by end of day Friday.\"\n\nQ: 출석 명단 제출 마감은?","opts":["화요일 종례","수요일 종례","금요일 종례","다음 주 월요일"],"ans":2,"exp":"'submit them to training by end of day Friday'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Today we examine building construction types and their fire behavior implications. Type I — fire resistive — uses non-combustible materials and typically withstands fire longest. Type V — wood frame — is the most common in residential construction and presents the greatest collapse risk due to rapid heat damage to structural members.\"\n\nQ: 화재 시 붕괴 위험이 가장 높은 건물 유형은?","opts":["Type I (내화)","Type II (비연소)","Type IV (중목재)","Type V (목조)"],"ans":3,"exp":"'Type V — wood frame ... greatest collapse risk'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"Type III construction — ordinary construction — combines non-combustible exterior walls with combustible interior framing. The void spaces within these walls allow fire to travel vertically unseen, a phenomenon known as balloon frame fire spread.\"\n\nQ: Type III 건물에서 화재가 눈에 보이지 않게 수직으로 확산하는 이유는?","opts":["알루미늄 외벽","벽 내 빈 공간","스프링클러 부재","목재 바닥"],"ans":1,"exp":"'void spaces within these walls allow fire to travel vertically unseen'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"A Personnel Accountability Report (PAR) is a roll call of all assigned personnel at defined intervals or triggered by significant events — a MAYDAY, sudden change in fire conditions, or transition from offensive to defensive operations.\"\n\nQ: PAR 실시를 트리거하는 사건이 아닌 것은?","opts":["MAYDAY 발령","화재 상황 급변","공세→수세 전환","정기 교대 시간"],"ans":3,"exp":"정기 교대 시간은 PAR 트리거로 언급되지 않음","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"The Phoenix Model of risk management — developed by the Phoenix Fire Department — states: risk a lot to save a savable life, risk a little to save savable property, and risk nothing to save what is already lost. This model has been widely adopted internationally.\"\n\nQ: Phoenix 모델에서 '이미 잃은 것을 구하기 위해' 감수해야 할 위험은?","opts":["최대한","약간","없음","상황에 따라"],"ans":2,"exp":"'risk nothing to save what is already lost'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Accountability at the fireground operates on three levels: individual accountability, where each firefighter knows their assignment; company accountability, where officers track their crew; and command accountability, where IC maintains situational awareness of all resources.\"\n\nQ: 지휘 책임(command accountability)의 핵심은?","opts":["개인 임무 파악","팀 추적","IC의 전체 자원 상황인식 유지","문서 작성"],"ans":2,"exp":"'IC maintains situational awareness of all resources'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Decision-making under stress follows two primary models: the classical analytical model, which evaluates multiple options systematically, and the Recognition-Primed Decision (RPD) model, developed by Gary Klein. RPD describes how experienced decision-makers use pattern recognition to rapidly identify a workable solution without comparing alternatives.\"\n\nQ: RPD 모델의 핵심 특징은?","opts":["모든 선택지 체계적 분석","패턴 인식으로 빠르게 실행 가능한 해결책 식별","팀 합의를 통한 결정","데이터 기반 의사결정"],"ans":1,"exp":"'pattern recognition to rapidly identify a workable solution without comparing alternatives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"Klein's research found that experienced firefighters rarely compare multiple options. Instead, they mentally simulate the chosen course of action to check for obvious flaws, then act. This mental simulation — 'if I do this, what happens?' — is a key feature of expert decision-making.\"\n\nQ: 숙련된 소방관의 의사결정에서 '정신적 시뮬레이션'의 역할은?","opts":["선택지 수를 늘림","선택된 행동 과정의 명백한 결함 확인","팀 전체에 결정 전달","문서 작성"],"ans":1,"exp":"'mentally simulate ... to check for obvious flaws'","section":"청취"},{"q":"\"Mayday procedures require: announcing MAYDAY three times, stating name and unit, describing the emergency, and providing location. The IC assigns a dedicated channel and activates the RIT.\"\n\nQ: MAYDAY 선언 시 가장 먼저 해야 하는 것은?","opts":["위치 알리기","MAYDAY 세 번 반복","RIT 가동","채널 변경"],"ans":1,"exp":"'announcing MAYDAY three times' → 가장 먼저 세 번 반복","section":"독해","passage":"X"},{"q":"\"Overhaul is the systematic process of searching the fire scene for hidden hot spots after the main fire is controlled. Thermal imaging cameras significantly enhance overhaul efficiency.\"\n\nQ: 잔화처리 중 열화상 카메라의 역할은?","opts":["화재 원인 조사","숨겨진 열점 탐지 효율 향상","통신 지원","건물 구조 분석"],"ans":1,"exp":"'Thermal imaging cameras significantly enhance overhaul efficiency'","section":"독해","passage":"X"},{"q":"\"Breathing air cylinders for SCBA must be hydrostatically tested every five years. Any cylinder showing corrosion, dents, or damage to the neck threads must be removed from service immediately.\"\n\nQ: SCBA 실린더를 즉시 사용 중단해야 하는 조건은?","opts":["5년 미경과","사용 횟수 초과","부식·움푹 팬 곳·목 나사산 손상","압력 약간 감소"],"ans":2,"exp":"'corrosion, dents, or damage to the neck threads'","section":"독해","passage":"X"},{"q":"\"Conflagrations — large fires that spread beyond their point of origin to involve multiple structures — require regional mutual aid and can overwhelm local resources. Historic conflagrations often reshape building codes and fire prevention strategies.\"\n\nQ: 대규모 화재(conflagration)의 장기적 영향은?","opts":["일시적 혼란","건축 법규·방화 전략 재편","보험 비용 감소","지역 경제 성장"],"ans":1,"exp":"'reshape building codes and fire prevention strategies'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'systematic'의 의미는?","opts":["random","methodical/organized","rapid","minimal"],"ans":1,"exp":"systematic = 체계적인(methodical/organized)","section":"독해","passage":"X"},{"q":"\"The staging area is a designated location where resources are assembled and await assignment. It is separate from the operational area to reduce congestion and improve coordination.\"\n\nQ: 대기 구역(staging area)이 작전 구역과 분리되는 이유는?","opts":["보안 유지","혼잡 감소 및 조율 향상","비용 절감","법적 요건"],"ans":1,"exp":"'reduce congestion and improve coordination'","section":"독해","passage":"X"},{"q":"\"Unified command is appropriate when an incident involves multiple jurisdictions or agencies with overlapping responsibilities. Each agency retains its own authority while contributing to a single Incident Action Plan.\"\n\nQ: 통합지휘가 적합한 상황은?","opts":["단일 기관 소규모 사고","다관할·다기관 중복 책임 사고","야간 단독 사고","훈련 중"],"ans":1,"exp":"'multiple jurisdictions or agencies with overlapping responsibilities'","section":"독해","passage":"X"},{"q":"\"Ground monitors — large-caliber nozzles positioned without requiring a firefighter to hold them — are used in defensive operations to deliver high-volume streams.\"\n\nQ: 지상 모니터의 주요 장점은?","opts":["높은 정밀도","소방관 없이 고용량 방수 가능","실내 전용","이동성"],"ans":1,"exp":"'without requiring a firefighter to hold them'","section":"독해","passage":"X"},{"q":"\"Salvage operations protect property from water, smoke, and overhaul damage after the main fire is controlled. Covers, mops, and squeegees are essential salvage tools.\"\n\nQ: 잔화처리(salvage) 작업의 주요 목적은?","opts":["잔불 제거","수색 실시","추가 피해로부터 재산 보호","화재 원인 조사"],"ans":2,"exp":"'protect property from water, smoke, and overhaul damage'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'salvage'의 의미는?","opts":["destruction","property protection after disaster","fire suppression","evacuation"],"ans":1,"exp":"salvage = 화재 후 재산 보호 작업","section":"독해","passage":"X"},{"q":"Q: 지문에서 'congestion'의 의미는?","opts":["danger","overcrowding/blockage","noise","delay"],"ans":1,"exp":"congestion = 혼잡, 밀집(overcrowding)","section":"독해","passage":"X"},{"q":"\"The incident action plan (IAP) is updated each operational period to reflect changing conditions. It documents objectives, strategies, tactics, and resource assignments.\"\n\nQ: IAP가 업데이트되는 시점은?","opts":["사고 시작 시 한 번","매 작전 기간마다","48시간마다","사고 종료 후"],"ans":1,"exp":"'updated each operational period'","section":"독해","passage":"X"},{"q":"\"Incident size-up is a continuous process that begins before arrival and continues throughout the incident. Key factors include: building construction, occupancy, life safety, fire extension, and available resources.\"\n\nQ: 상황평가(size-up)는 언제 시작하는가?","opts":["현장 도착 후","내부 진입 후","도착 전부터 지속적으로","지휘소 설치 후"],"ans":2,"exp":"'begins before arrival and continues throughout'","section":"독해","passage":"X"},{"q":"\"Water curtains can be used to protect exposures from radiant heat during large fires. They create a water barrier between the burning structure and adjacent buildings.\"\n\nQ: 수막(water curtain)의 용도는?","opts":["화재 직접 진압","복사열로부터 인접 건물 보호","시야 확보","연기 제거"],"ans":1,"exp":"'protect exposures from radiant heat'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'occupancy loads'의 의미는?","opts":["weight limits","number of people in a building","utility capacity","fire load"],"ans":1,"exp":"occupancy load = 건물 재실 인원 수","section":"독해","passage":"X"},{"q":"\"Preplanning visits allow fire crews to familiarize themselves with building layouts, hazards, utility shutoffs, and occupancy loads. Buildings with completed preplans consistently show better outcomes during actual incidents.\"\n\nQ: 사전 계획 방문의 이점은?","opts":["건물 소유자와 관계 형성","대응 효과 향상","법적 면책","건물 코드 검사"],"ans":1,"exp":"'better outcomes during actual incidents'","section":"독해","passage":"X"},{"q":"\"Firefighter fatalities from cardiac events account for nearly 45% of line-of-duty deaths annually. Regular cardiovascular fitness assessments and mandatory medical evaluations are now standard in most departments.\"\n\nQ: 심장 관련 사망이 전체의 몇 퍼센트를 차지하는가?","opts":["약 25%","약 35%","약 45%","약 55%"],"ans":2,"exp":"'nearly 45% of line-of-duty deaths'","section":"독해","passage":"X"},{"q":"\"FIRESCOPE (Firefighting Resources of Southern California Organized for Potential Emergencies) was the collaborative effort that formalized ICS. It emerged from lessons learned during the 1970 Laguna and Claremont fires.\"\n\nQ: FIRESCOPE의 기원이 된 사건은?","opts":["1980년대 허리케인","1970년 Laguna·Claremont 산불","9/11 테러","1990년대 홍수"],"ans":1,"exp":"'emerged from lessons learned during the 1970 Laguna and Claremont fires'","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'formalized'의 의미는?","opts":["ignored","made official/structured","challenged","simplified"],"ans":1,"exp":"formalized = 공식화했다(made official)","section":"독해","passage":"EX"},{"q":"\"FIRESCOPE established common terminology, unified command, and modular organization — concepts that became the foundation of ICS and later NIMS.\"\n\nQ: FIRESCOPE가 확립한 개념이 아닌 것은?","opts":["공통 용어","통합 지휘","모듈 조직","드론 운용"],"ans":3,"exp":"드론 운용은 FIRESCOPE 당시(1970년대) 개념이 아님","section":"독해","passage":"EX"},{"q":"\"THINCS identifies eight key NTS domains: situational awareness, decision-making, communication, leadership, teamwork, task management, stress management, and adaptability.\"\n\nQ: THINCS의 NTS 8개 영역이 아닌 것은?","opts":["상황인식","장비 조작","스트레스 관리","적응력"],"ans":1,"exp":"장비 조작(equipment operation)은 NTS가 아닌 기술적 역량","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'integrates'의 의미는?","opts":["separates","combines into one","evaluates","removes"],"ans":1,"exp":"integrates = 통합하다(combines into one)","section":"독해","passage":"EX"},{"q":"\"The UK THINCS model (Tactical, Human, Incident, Non-technical Command Skills) integrates technical and non-technical competencies into a single framework for evaluating incident commanders.\"\n\nQ: THINCS 모델의 특징은?","opts":["기술 역량만 평가","기술·비기술 역량 통합 평가","인원 관리 전용","장비 평가 도구"],"ans":1,"exp":"'integrates technical and non-technical competencies'","section":"독해","passage":"EX"},{"q":"\"The Phoenix Fire Department pioneered the 'risk a lot to save a lot, risk a little to save a little, risk nothing to save nothing' doctrine. This framework guides commanders in calibrating risk levels based on what can be gained.\"\n\nQ: 이 원칙이 지휘관에게 제공하는 것은?","opts":["엄격한 절차","상황별 위험 조율 기준","새 장비 지침","법적 근거"],"ans":1,"exp":"'guides commanders in calibrating risk levels based on what can be gained'","section":"독해","passage":"EX"},{"q":"\"Risk a nothing to save nothing' applies when there is no potential for life safety — for example, when a structure is fully involved and confirmed unoccupied. In such cases, defensive operations protect firefighters.\"\n\nQ: '아무것도 걸지 않는다' 원칙을 적용하는 상황은?","opts":["생존자 확인 시","구조물이 완전 연소되고 비어있음이 확인된 때","소형 화재","야간 작전"],"ans":1,"exp":"'when structure is fully involved and confirmed unoccupied'","section":"독해","passage":"EX"},{"q":"\"The incident commander is responsible for the overall management of the incident. This includes establishing objectives, ordering resources, and ensuring the safety of all personnel.\"\n\nQ: 사고지휘관의 책임이 아닌 것은?","opts":["목표 수립","자원 요청","전체 관리","개인 소방 장비 점검"],"ans":3,"exp":"개인 장비 점검은 개인 책임, 지휘관 직무 아님","section":"독해","passage":"Y"},{"q":"\"Fire flow is the quantity of water required for fire suppression, expressed in gallons per minute (gpm). It depends on building size, construction type, and fire load.\"\n\nQ: 지문에서 'fire flow'에 영향을 주는 요소가 아닌 것은?","opts":["건물 크기","건물 구조 유형","화재 부하","기상 조건"],"ans":3,"exp":"기상 조건은 fire flow 결정 요소로 언급되지 않음","section":"독해","passage":"Y"},{"q":"Q: 지문에서 'suppression'의 의미는?","opts":["ignition","extinguishment/control","spread","detection"],"ans":1,"exp":"fire suppression = 화재 진압·통제(extinguishment/control)","section":"독해","passage":"Y"}]},{"round":2,"title":"제2회 기출 유형","analysis":{"summary":"도치 구문(Not until, Only then), 가정법-wish, 분사구문 Having p.p. 고난도 문법 집중. 청취 Part2 긴 대화·Part3 담화문, 독해 fire behavior·NTS 지문.","tips":["도치: 부정어 문두 → 조동사+주어+동사","wish+had = 현재 반대, wish+had p.p. = 과거 반대","Having p.p. = 주절보다 이전에 완료된 동작"]},"qs":[{"type":"현재완료","q":"The unit _____ on standby since 0600.","opts":["is","was","has been","had been"],"ans":2,"exp":"since+시점 → 현재완료(has been)","section":"문법"},{"type":"과거완료","q":"The evacuation _____ completed before the structure collapsed.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거(collapsed) → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"가정법 과거","q":"If the equipment _____ in better condition, the task would be easier.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"가정법 과거완료","q":"If the team _____ the warning, the firefighter would not have been injured.","opts":["heeded","heeds","had heeded","has heeded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., would have p.p.","section":"문법"},{"type":"준동사-동명사","q":"The chief recommended _____ all rooftop access points before committing crews.","opts":["to assess","assess","assessing","assessed"],"ans":2,"exp":"recommend+동명사(V-ing)","section":"문법"},{"type":"준동사-to부정사","q":"The department agreed _____ the new accountability system by January.","opts":["implement","implementing","to implement","implemented"],"ans":2,"exp":"agree+to부정사","section":"문법"},{"type":"관계사-who","q":"The medic _____ treated the burn victims received a commendation.","opts":["who","which","whose","whom"],"ans":0,"exp":"사람 선행사+주어 역할 → who","section":"문법"},{"type":"관계사-whose","q":"The officer _____ unit responded first was praised for the fastest deployment.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"조동사-must","q":"The radio must _____ malfunctioned — no transmissions were received.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측","section":"문법"},{"type":"조동사-should","q":"The crew should _____ performed a 360-degree walkthrough before entry.","opts":["have","had","be","has"],"ans":0,"exp":"should have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"수동태","q":"The incident report _____ finalized before the press briefing.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"미래완료","q":"By next Tuesday, the department _____ its centennial celebrations.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by+미래시점 → 미래완료(will have p.p.)","section":"문법"},{"type":"부정사 구문","q":"The regulation requires all units _____ before entering IDLH environments.","opts":["check","checking","to check","checked"],"ans":2,"exp":"require+목적어+to부정사: requires A to V","section":"문법"},{"type":"가정법-wish","q":"The firefighter wishes she _____ more time to practice the drill.","opts":["has","had","would have","will have"],"ans":1,"exp":"wish+가정법 과거: wish+주어+had → 현재 사실 반대","section":"문법"},{"type":"준동사-지각동사","q":"The supervisor heard the team _____ the evacuation alarm.","opts":["to activate","activating","activated","activation"],"ans":1,"exp":"지각동사(hear)+목적어+V-ing(진행 중인 동작)","section":"문법"},{"type":"간접의문문","q":"Could you tell me _____ the drill starts?","opts":["when does","when","what time does","that when"],"ans":1,"exp":"간접의문문: 의문사+주어+동사(정상 어순)","section":"문법"},{"type":"간접의문문","q":"The chief asked _____ the new recruits had passed their fitness test.","opts":["that whether","if","whether that","that"],"ans":1,"exp":"간접의문문: asked if/whether+주어+동사","section":"문법"},{"type":"관계부사","q":"The protocol explains the reason _____ all aerial operations were suspended.","opts":["which","that","why","for which"],"ans":2,"exp":"reason+why = 이유 관계부사(= for which)","section":"문법"},{"type":"복합 관계사","q":"The commander approved _____ the safety officer recommended.","opts":["that","which","what","who"],"ans":2,"exp":"선행사 없는 명사절 목적어 → what(~하는 것을)","section":"문법"},{"type":"준동사-사역동사","q":"The chief had the recruits _____ the drill twice.","opts":["repeat","to repeat","repeating","repeated"],"ans":0,"exp":"사역동사(have)+목적어+동사원형","section":"문법"},{"type":"복합 시제","q":"By the time you read this report, the investigation _____ for a week.","opts":["will run","will be running","will have been running","runs"],"ans":2,"exp":"by the time+현재 → 미래완료진행(will have been V-ing)","section":"문법"},{"type":"분사구문","q":"The alarm _____ at midnight, all off-duty personnel were immediately recalled.","opts":["sounding","having sounded","sounded","to sound"],"ans":1,"exp":"Having p.p. = 경보가 울린 후 → 수동 분사구문","section":"문법"},{"type":"도치","q":"Only then _____ the true extent of the damage.","opts":["they realized","did they realize","they did realize","realized they"],"ans":1,"exp":"Only+부사 문두 → 조동사+주어 도치","section":"문법"},{"type":"가정법-wish","q":"I wish the department _____ adopted the new protocol earlier.","opts":["has","had","would have","will have"],"ans":1,"exp":"wish+가정법 과거완료: wish+주어+had p.p. → 과거 사실 반대","section":"문법"},{"type":"도치","q":"Not until the building was secured _____ allowed to enter.","opts":["the crew was","was the crew","the crew is","is the crew"],"ans":1,"exp":"부정어(Not until) 문두 → 주어·동사 도치","section":"문법"},{"type":"분사구문","q":"_____ all exits, the safety team confirmed the building was clear.","opts":["Checking","Having checked","To check","Checked"],"ans":1,"exp":"분사구문: Having p.p. = 주절보다 이전에 완료된 동작","section":"문법"},{"part":1,"q":"[Part 1] \"Did all personnel make it out of the collapse zone?\"\n\"All accounted for — PAR was clear.\"\n\nQ: 붕괴 구역 인원 현황은?","opts":["1명 행방불명","전원 확인 완료","2명 부상","PAR 미실시"],"ans":1,"exp":"'All accounted for — PAR was clear'","section":"청취"},{"part":1,"q":"[Part 1] \"Has the gas been shut off?\"\n\"The utility company confirmed it was isolated at 0312.\"\n\nQ: 가스 차단 시간은?","opts":["0212","0312","0412","0512"],"ans":1,"exp":"'isolated at 0312'","section":"청취"},{"part":1,"q":"[Part 1] \"Are there any exposures we need to protect?\"\n\"The east wall is about fifteen feet from an occupied residential building.\"\n\nQ: 노출 위험 건물의 위치는?","opts":["서쪽 15피트","동쪽 15피트","북쪽 20피트","남쪽 10피트"],"ans":1,"exp":"'east wall ... fifteen feet from residential building'","section":"청취"},{"part":1,"q":"[Part 1] \"How many civilians were displaced by the fire?\"\n\"Forty-three. The Red Cross has set up a shelter at the community center.\"\n\nQ: 이재민 수용 장소는?","opts":["학교","소방서","지역 센터","호텔"],"ans":2,"exp":"'Red Cross ... shelter at the community center'","section":"청취"},{"part":1,"q":"[Part 1] \"Is the water supply adequate for a prolonged operation?\"\n\"We've got two hydrants on Oak and Main — should be sufficient.\"\n\nQ: 사용 가능한 소화전 수는?","opts":["1개","2개","3개","4개"],"ans":1,"exp":"'two hydrants on Oak and Main'","section":"청취"},{"part":1,"q":"[Part 1] \"Is the incident commander still on scene?\"\n\"He handed off to Battalion Chief Park about an hour ago.\"\n\nQ: 현재 사고지휘관은?","opts":["원래 지휘관","Park 대대장","부서장","훈련 지휘관"],"ans":1,"exp":"'handed off to Battalion Chief Park'","section":"청취"},{"part":1,"q":"[Part 1] \"Did the building owner provide access to the utility room?\"\n\"Eventually — took about twenty minutes of negotiation.\"\n\nQ: 다용도실 접근은?","opts":["즉시 허용","약 20분 협상 후 허용","거부됨","경찰이 강제 진입"],"ans":1,"exp":"'took about twenty minutes of negotiation'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"When should we hold the press conference?\"\n\"Let's aim for Thursday — that gives us two days to compile the full timeline and coordinate with the mayor's office.\"\n\nQ: 기자회견 예정일은?","opts":["화요일","수요일","목요일","금요일"],"ans":2,"exp":"'aim for Thursday'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"What's the main takeaway from this incident?\"\n\"Coordination between ventilation and attack teams needs to be tighter. We'll add that to the drill curriculum.\"\n\nQ: 주요 개선 사항은?","opts":["RIT 배치 변경","환기-진압 팀 조율 강화","진입 시점 교정","MAYDAY 절차 수정"],"ans":1,"exp":"'Coordination between ventilation and attack teams needs to be tighter'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"Good catch. Make sure overhaul protocols include mandatory thermal imaging of adjacent walls going forward.\"\n\"Already drafting the SOG update. I'll have it ready by next shift.\"\n\nQ: SOG 업데이트 완료 예정 시점은?","opts":["오늘 중","다음 교대 전","다음 주","한 달 이내"],"ans":1,"exp":"'ready by next shift'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The post-incident analysis showed three critical decision points where the outcome could have been different.\"\n\"Which ones?\"\n\"Entry timing, ventilation coordination, and RIT positioning. If any one of those had gone differently, we might have had a mayday.\"\n\nQ: 분석에서 밝혀진 결정적 실수 수는?","opts":["1가지","2가지","3가지","4가지"],"ans":2,"exp":"'three critical decision points'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The thermal camera flagged a hot spot on the east wall during overhaul.\"\n\"Did the crew investigate it?\"\n\"Yes — they opened up about four feet of wall and found smoldering insulation. It was extinguished, but it could have rekindled overnight.\"\n\nQ: 동쪽 벽에서 발견된 것은?","opts":["가스관 손상","훈소하는 단열재","전기 화재 흔적","구조적 손상"],"ans":1,"exp":"'smoldering insulation'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The community is demanding a public explanation for the response delay.\"\n\"I understand. We need to be transparent. Let's schedule a press conference and walk them through the timeline.\"\n\"Should we involve legal counsel?\"\n\"Yes — standard procedure for any incident that draws this level of scrutiny.\"\n\nQ: 대응 지연에 대한 결정된 조치는?","opts":["언론 보도 차단","법적 대응 거부","기자회견 개최 및 타임라인 공개","관계자 즉시 징계"],"ans":2,"exp":"'schedule a press conference and walk them through the timeline'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"A reminder that all annual SCBA fit tests must be completed before the end of the quarter. If you have not yet scheduled yours, contact the equipment coordinator immediately. Personnel who fail to complete the test will be placed on restricted duty until compliance is achieved.\"\n\nQ: 적합성 시험 미완료 시 결과는?","opts":["급여 삭감","징계 처분","제한 근무 배치","즉시 휴직"],"ans":2,"exp":"'placed on restricted duty until compliance is achieved'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"The new Personnel Accountability System goes live on the first of next month. Every firefighter will be issued a new accountability tag embedded with an RFID chip. These replace the old dog-tag system. Failure to carry your tag while on duty will result in a written warning on first offense, and suspension on the second.\"\n\nQ: 태그 미소지 시 두 번째 위반 처벌은?","opts":["구두 경고","서면 경고","정직","해임"],"ans":2,"exp":"'suspension on the second'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Effective immediately, all incident commanders must submit a written size-up report within 30 minutes of arrival at any working structure fire. The report must include: life safety status, fire conditions, building construction type, and resource needs. Forms are available in the command vehicle.\"\n\nQ: 30분 이내 보고서에 포함해야 할 항목이 아닌 것은?","opts":["인명 안전 현황","화재 조건","건물 구조 유형","화재 원인 추정"],"ans":3,"exp":"화재 원인 추정은 언급된 4개 항목에 없음","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Tonight's scene involves a suspected natural gas leak in a residential neighborhood. Evacuate a two-block radius. No motorized vehicles, open flames, or electrical operation within that zone. Once the utility company confirms isolation, ventilate the affected structures before allowing any re-entry.\"\n\nQ: 가스 차단 확인 후 재진입 전 해야 할 것은?","opts":["구조물 사진 촬영","인근 건물 수색","영향받은 구조물 환기","전기 공급 복구"],"ans":2,"exp":"'ventilate the affected structures before allowing any re-entry'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"The department will be conducting a multi-agency disaster drill on the 18th. Participating agencies include fire, EMS, law enforcement, and public works. All personnel should be in uniform and report to the staging area at 0700. Observers from city hall will be present, so professionalism is expected.\"\n\nQ: 훈련에 참여하지 않는 기관은?","opts":["소방","의료","법 집행","공중 보건"],"ans":3,"exp":"public works(공공 작업)가 있지만 공중 보건(public health)은 언급되지 않음","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Following last month's near-miss incident, all engine companies will participate in a mandatory hose load refresher. The training will be conducted in three sessions this week: Tuesday, Wednesday, and Friday. All company officers must sign attendance sheets and submit them to training by end of day Friday.\"\n\nQ: 출석 명단 제출 마감은?","opts":["화요일 종례","수요일 종례","금요일 종례","다음 주 월요일"],"ans":2,"exp":"'submit them to training by end of day Friday'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Today we examine building construction types and their fire behavior implications. Type I — fire resistive — uses non-combustible materials and typically withstands fire longest. Type V — wood frame — is the most common in residential construction and presents the greatest collapse risk due to rapid heat damage to structural members.\"\n\nQ: 화재 시 붕괴 위험이 가장 높은 건물 유형은?","opts":["Type I (내화)","Type II (비연소)","Type IV (중목재)","Type V (목조)"],"ans":3,"exp":"'Type V — wood frame ... greatest collapse risk'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"Type III construction — ordinary construction — combines non-combustible exterior walls with combustible interior framing. The void spaces within these walls allow fire to travel vertically unseen, a phenomenon known as balloon frame fire spread.\"\n\nQ: Type III 건물에서 화재가 눈에 보이지 않게 수직으로 확산하는 이유는?","opts":["알루미늄 외벽","벽 내 빈 공간","스프링클러 부재","목재 바닥"],"ans":1,"exp":"'void spaces within these walls allow fire to travel vertically unseen'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Decision-making under stress follows two primary models: the classical analytical model, which evaluates multiple options systematically, and the Recognition-Primed Decision (RPD) model, developed by Gary Klein. RPD describes how experienced decision-makers use pattern recognition to rapidly identify a workable solution without comparing alternatives.\"\n\nQ: RPD 모델의 핵심 특징은?","opts":["모든 선택지 체계적 분석","패턴 인식으로 빠르게 실행 가능한 해결책 식별","팀 합의를 통한 결정","데이터 기반 의사결정"],"ans":1,"exp":"'pattern recognition to rapidly identify a workable solution without comparing alternatives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Accountability at the fireground operates on three levels: individual accountability, where each firefighter knows their assignment; company accountability, where officers track their crew; and command accountability, where IC maintains situational awareness of all resources.\"\n\nQ: 지휘 책임(command accountability)의 핵심은?","opts":["개인 임무 파악","팀 추적","IC의 전체 자원 상황인식 유지","문서 작성"],"ans":2,"exp":"'IC maintains situational awareness of all resources'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"The Phoenix Model of risk management — developed by the Phoenix Fire Department — states: risk a lot to save a savable life, risk a little to save savable property, and risk nothing to save what is already lost. This model has been widely adopted internationally.\"\n\nQ: Phoenix 모델에서 '이미 잃은 것을 구하기 위해' 감수해야 할 위험은?","opts":["최대한","약간","없음","상황에 따라"],"ans":2,"exp":"'risk nothing to save what is already lost'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"Klein's research found that experienced firefighters rarely compare multiple options. Instead, they mentally simulate the chosen course of action to check for obvious flaws, then act. This mental simulation — 'if I do this, what happens?' — is a key feature of expert decision-making.\"\n\nQ: 숙련된 소방관의 의사결정에서 '정신적 시뮬레이션'의 역할은?","opts":["선택지 수를 늘림","선택된 행동 과정의 명백한 결함 확인","팀 전체에 결정 전달","문서 작성"],"ans":1,"exp":"'mentally simulate ... to check for obvious flaws'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"A Personnel Accountability Report (PAR) is a roll call of all assigned personnel at defined intervals or triggered by significant events — a MAYDAY, sudden change in fire conditions, or transition from offensive to defensive operations.\"\n\nQ: PAR 실시를 트리거하는 사건이 아닌 것은?","opts":["MAYDAY 발령","화재 상황 급변","공세→수세 전환","정기 교대 시간"],"ans":3,"exp":"정기 교대 시간은 PAR 트리거로 언급되지 않음","section":"청취"},{"q":"Q: 지문에서 'congestion'의 의미는?","opts":["danger","overcrowding/blockage","noise","delay"],"ans":1,"exp":"congestion = 혼잡, 밀집(overcrowding)","section":"독해","passage":"X"},{"q":"\"Salvage operations protect property from water, smoke, and overhaul damage after the main fire is controlled. Covers, mops, and squeegees are essential salvage tools.\"\n\nQ: 잔화처리(salvage) 작업의 주요 목적은?","opts":["잔불 제거","수색 실시","추가 피해로부터 재산 보호","화재 원인 조사"],"ans":2,"exp":"'protect property from water, smoke, and overhaul damage'","section":"독해","passage":"X"},{"q":"\"Conflagrations — large fires that spread beyond their point of origin to involve multiple structures — require regional mutual aid and can overwhelm local resources. Historic conflagrations often reshape building codes and fire prevention strategies.\"\n\nQ: 대규모 화재(conflagration)의 장기적 영향은?","opts":["일시적 혼란","건축 법규·방화 전략 재편","보험 비용 감소","지역 경제 성장"],"ans":1,"exp":"'reshape building codes and fire prevention strategies'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'systematic'의 의미는?","opts":["random","methodical/organized","rapid","minimal"],"ans":1,"exp":"systematic = 체계적인(methodical/organized)","section":"독해","passage":"X"},{"q":"\"Overhaul is the systematic process of searching the fire scene for hidden hot spots after the main fire is controlled. Thermal imaging cameras significantly enhance overhaul efficiency.\"\n\nQ: 잔화처리 중 열화상 카메라의 역할은?","opts":["화재 원인 조사","숨겨진 열점 탐지 효율 향상","통신 지원","건물 구조 분석"],"ans":1,"exp":"'Thermal imaging cameras significantly enhance overhaul efficiency'","section":"독해","passage":"X"},{"q":"\"Breathing air cylinders for SCBA must be hydrostatically tested every five years. Any cylinder showing corrosion, dents, or damage to the neck threads must be removed from service immediately.\"\n\nQ: SCBA 실린더를 즉시 사용 중단해야 하는 조건은?","opts":["5년 미경과","사용 횟수 초과","부식·움푹 팬 곳·목 나사산 손상","압력 약간 감소"],"ans":2,"exp":"'corrosion, dents, or damage to the neck threads'","section":"독해","passage":"X"},{"q":"\"Incident size-up is a continuous process that begins before arrival and continues throughout the incident. Key factors include: building construction, occupancy, life safety, fire extension, and available resources.\"\n\nQ: 상황평가(size-up)는 언제 시작하는가?","opts":["현장 도착 후","내부 진입 후","도착 전부터 지속적으로","지휘소 설치 후"],"ans":2,"exp":"'begins before arrival and continues throughout'","section":"독해","passage":"X"},{"q":"\"Ground monitors — large-caliber nozzles positioned without requiring a firefighter to hold them — are used in defensive operations to deliver high-volume streams.\"\n\nQ: 지상 모니터의 주요 장점은?","opts":["높은 정밀도","소방관 없이 고용량 방수 가능","실내 전용","이동성"],"ans":1,"exp":"'without requiring a firefighter to hold them'","section":"독해","passage":"X"},{"q":"\"The incident action plan (IAP) is updated each operational period to reflect changing conditions. It documents objectives, strategies, tactics, and resource assignments.\"\n\nQ: IAP가 업데이트되는 시점은?","opts":["사고 시작 시 한 번","매 작전 기간마다","48시간마다","사고 종료 후"],"ans":1,"exp":"'updated each operational period'","section":"독해","passage":"X"},{"q":"\"Firefighter fatalities from cardiac events account for nearly 45% of line-of-duty deaths annually. Regular cardiovascular fitness assessments and mandatory medical evaluations are now standard in most departments.\"\n\nQ: 심장 관련 사망이 전체의 몇 퍼센트를 차지하는가?","opts":["약 25%","약 35%","약 45%","약 55%"],"ans":2,"exp":"'nearly 45% of line-of-duty deaths'","section":"독해","passage":"X"},{"q":"\"Unified command is appropriate when an incident involves multiple jurisdictions or agencies with overlapping responsibilities. Each agency retains its own authority while contributing to a single Incident Action Plan.\"\n\nQ: 통합지휘가 적합한 상황은?","opts":["단일 기관 소규모 사고","다관할·다기관 중복 책임 사고","야간 단독 사고","훈련 중"],"ans":1,"exp":"'multiple jurisdictions or agencies with overlapping responsibilities'","section":"독해","passage":"X"},{"q":"\"Water curtains can be used to protect exposures from radiant heat during large fires. They create a water barrier between the burning structure and adjacent buildings.\"\n\nQ: 수막(water curtain)의 용도는?","opts":["화재 직접 진압","복사열로부터 인접 건물 보호","시야 확보","연기 제거"],"ans":1,"exp":"'protect exposures from radiant heat'","section":"독해","passage":"X"},{"q":"\"The staging area is a designated location where resources are assembled and await assignment. It is separate from the operational area to reduce congestion and improve coordination.\"\n\nQ: 대기 구역(staging area)이 작전 구역과 분리되는 이유는?","opts":["보안 유지","혼잡 감소 및 조율 향상","비용 절감","법적 요건"],"ans":1,"exp":"'reduce congestion and improve coordination'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'salvage'의 의미는?","opts":["destruction","property protection after disaster","fire suppression","evacuation"],"ans":1,"exp":"salvage = 화재 후 재산 보호 작업","section":"독해","passage":"X"},{"q":"\"Mayday procedures require: announcing MAYDAY three times, stating name and unit, describing the emergency, and providing location. The IC assigns a dedicated channel and activates the RIT.\"\n\nQ: MAYDAY 선언 시 가장 먼저 해야 하는 것은?","opts":["위치 알리기","MAYDAY 세 번 반복","RIT 가동","채널 변경"],"ans":1,"exp":"'announcing MAYDAY three times' → 가장 먼저 세 번 반복","section":"독해","passage":"X"},{"q":"Q: 지문에서 'occupancy loads'의 의미는?","opts":["weight limits","number of people in a building","utility capacity","fire load"],"ans":1,"exp":"occupancy load = 건물 재실 인원 수","section":"독해","passage":"X"},{"q":"\"Preplanning visits allow fire crews to familiarize themselves with building layouts, hazards, utility shutoffs, and occupancy loads. Buildings with completed preplans consistently show better outcomes during actual incidents.\"\n\nQ: 사전 계획 방문의 이점은?","opts":["건물 소유자와 관계 형성","대응 효과 향상","법적 면책","건물 코드 검사"],"ans":1,"exp":"'better outcomes during actual incidents'","section":"독해","passage":"X"},{"q":"\"THINCS identifies eight key NTS domains: situational awareness, decision-making, communication, leadership, teamwork, task management, stress management, and adaptability.\"\n\nQ: THINCS의 NTS 8개 영역이 아닌 것은?","opts":["상황인식","장비 조작","스트레스 관리","적응력"],"ans":1,"exp":"장비 조작(equipment operation)은 NTS가 아닌 기술적 역량","section":"독해","passage":"EX"},{"q":"\"The Phoenix Fire Department pioneered the 'risk a lot to save a lot, risk a little to save a little, risk nothing to save nothing' doctrine. This framework guides commanders in calibrating risk levels based on what can be gained.\"\n\nQ: 이 원칙이 지휘관에게 제공하는 것은?","opts":["엄격한 절차","상황별 위험 조율 기준","새 장비 지침","법적 근거"],"ans":1,"exp":"'guides commanders in calibrating risk levels based on what can be gained'","section":"독해","passage":"EX"},{"q":"\"The UK THINCS model (Tactical, Human, Incident, Non-technical Command Skills) integrates technical and non-technical competencies into a single framework for evaluating incident commanders.\"\n\nQ: THINCS 모델의 특징은?","opts":["기술 역량만 평가","기술·비기술 역량 통합 평가","인원 관리 전용","장비 평가 도구"],"ans":1,"exp":"'integrates technical and non-technical competencies'","section":"독해","passage":"EX"},{"q":"\"FIRESCOPE established common terminology, unified command, and modular organization — concepts that became the foundation of ICS and later NIMS.\"\n\nQ: FIRESCOPE가 확립한 개념이 아닌 것은?","opts":["공통 용어","통합 지휘","모듈 조직","드론 운용"],"ans":3,"exp":"드론 운용은 FIRESCOPE 당시(1970년대) 개념이 아님","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'formalized'의 의미는?","opts":["ignored","made official/structured","challenged","simplified"],"ans":1,"exp":"formalized = 공식화했다(made official)","section":"독해","passage":"EX"},{"q":"\"Risk a nothing to save nothing' applies when there is no potential for life safety — for example, when a structure is fully involved and confirmed unoccupied. In such cases, defensive operations protect firefighters.\"\n\nQ: '아무것도 걸지 않는다' 원칙을 적용하는 상황은?","opts":["생존자 확인 시","구조물이 완전 연소되고 비어있음이 확인된 때","소형 화재","야간 작전"],"ans":1,"exp":"'when structure is fully involved and confirmed unoccupied'","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'pioneered'의 의미는?","opts":["criticized","followed","developed/led the way","rejected"],"ans":2,"exp":"pioneered = 선구적으로 개척했다","section":"독해","passage":"EX"},{"q":"\"FIRESCOPE (Firefighting Resources of Southern California Organized for Potential Emergencies) was the collaborative effort that formalized ICS. It emerged from lessons learned during the 1970 Laguna and Claremont fires.\"\n\nQ: FIRESCOPE의 기원이 된 사건은?","opts":["1980년대 허리케인","1970년 Laguna·Claremont 산불","9/11 테러","1990년대 홍수"],"ans":1,"exp":"'emerged from lessons learned during the 1970 Laguna and Claremont fires'","section":"독해","passage":"EX"},{"q":"\"The incident commander is responsible for the overall management of the incident. This includes establishing objectives, ordering resources, and ensuring the safety of all personnel.\"\n\nQ: 사고지휘관의 책임이 아닌 것은?","opts":["목표 수립","자원 요청","전체 관리","개인 소방 장비 점검"],"ans":3,"exp":"개인 장비 점검은 개인 책임, 지휘관 직무 아님","section":"독해","passage":"Y"},{"q":"\"Fire flow is the quantity of water required for fire suppression, expressed in gallons per minute (gpm). It depends on building size, construction type, and fire load.\"\n\nQ: 지문에서 'fire flow'에 영향을 주는 요소가 아닌 것은?","opts":["건물 크기","건물 구조 유형","화재 부하","기상 조건"],"ans":3,"exp":"기상 조건은 fire flow 결정 요소로 언급되지 않음","section":"독해","passage":"Y"},{"q":"Q: 지문에서 'suppression'의 의미는?","opts":["ignition","extinguishment/control","spread","detection"],"ans":1,"exp":"fire suppression = 화재 진압·통제(extinguishment/control)","section":"독해","passage":"Y"}]},{"round":3,"title":"제3회 기출 유형","analysis":{"summary":"복합 관계사(what·why·when), 강조구문(It is...that), 간접의문문, 복합 시제(미래완료진행). 청취 MAYDAY·책임 추적 담화, 독해 HAZMAT·고층 건물 지문.","tips":["What = 선행사 포함 명사절 ('~하는 것')","강조구문 It is X that Y → that 고정","간접의문문: 의문사+주어+동사(정상 어순)"]},"qs":[{"type":"현재완료","q":"The unit _____ on standby since 0600.","opts":["is","was","has been","had been"],"ans":2,"exp":"since+시점 → 현재완료(has been)","section":"문법"},{"type":"과거완료","q":"The evacuation _____ completed before the structure collapsed.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거(collapsed) → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"가정법 과거","q":"If the equipment _____ in better condition, the task would be easier.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"가정법 과거완료","q":"If the team _____ the warning, the firefighter would not have been injured.","opts":["heeded","heeds","had heeded","has heeded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., would have p.p.","section":"문법"},{"type":"준동사-동명사","q":"The chief recommended _____ all rooftop access points before committing crews.","opts":["to assess","assess","assessing","assessed"],"ans":2,"exp":"recommend+동명사(V-ing)","section":"문법"},{"type":"준동사-to부정사","q":"The department agreed _____ the new accountability system by January.","opts":["implement","implementing","to implement","implemented"],"ans":2,"exp":"agree+to부정사","section":"문법"},{"type":"관계사-who","q":"The medic _____ treated the burn victims received a commendation.","opts":["who","which","whose","whom"],"ans":0,"exp":"사람 선행사+주어 역할 → who","section":"문법"},{"type":"관계사-whose","q":"The officer _____ unit responded first was praised for the fastest deployment.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"조동사-must","q":"The radio must _____ malfunctioned — no transmissions were received.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측","section":"문법"},{"type":"조동사-should","q":"The crew should _____ performed a 360-degree walkthrough before entry.","opts":["have","had","be","has"],"ans":0,"exp":"should have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"수동태","q":"The incident report _____ finalized before the press briefing.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"미래완료","q":"By next Tuesday, the department _____ its centennial celebrations.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by+미래시점 → 미래완료(will have p.p.)","section":"문법"},{"type":"복합 시제","q":"By the time you read this report, the investigation _____ for a week.","opts":["will run","will be running","will have been running","runs"],"ans":2,"exp":"by the time+현재 → 미래완료진행(will have been V-ing)","section":"문법"},{"type":"부정사 구문","q":"The regulation requires all units _____ before entering IDLH environments.","opts":["check","checking","to check","checked"],"ans":2,"exp":"require+목적어+to부정사: requires A to V","section":"문법"},{"type":"분사구문","q":"The alarm _____ at midnight, all off-duty personnel were immediately recalled.","opts":["sounding","having sounded","sounded","to sound"],"ans":1,"exp":"Having p.p. = 경보가 울린 후 → 수동 분사구문","section":"문법"},{"type":"준동사-사역동사","q":"The chief had the recruits _____ the drill twice.","opts":["repeat","to repeat","repeating","repeated"],"ans":0,"exp":"사역동사(have)+목적어+동사원형","section":"문법"},{"type":"복합 관계사","q":"The commander approved _____ the safety officer recommended.","opts":["that","which","what","who"],"ans":2,"exp":"선행사 없는 명사절 목적어 → what(~하는 것을)","section":"문법"},{"type":"강조구문","q":"It was the outdated equipment _____ caused the malfunction.","opts":["which","that","who","what"],"ans":1,"exp":"강조구문(It is ... that): It was X that Y → that 고정","section":"문법"},{"type":"간접의문문","q":"Could you tell me _____ the drill starts?","opts":["when does","when","what time does","that when"],"ans":1,"exp":"간접의문문: 의문사+주어+동사(정상 어순)","section":"문법"},{"type":"분사구문","q":"_____ all exits, the safety team confirmed the building was clear.","opts":["Checking","Having checked","To check","Checked"],"ans":1,"exp":"분사구문: Having p.p. = 주절보다 이전에 완료된 동작","section":"문법"},{"type":"간접의문문","q":"The chief asked _____ the new recruits had passed their fitness test.","opts":["that whether","if","whether that","that"],"ans":1,"exp":"간접의문문: asked if/whether+주어+동사","section":"문법"},{"type":"준동사-지각동사","q":"The supervisor heard the team _____ the evacuation alarm.","opts":["to activate","activating","activated","activation"],"ans":1,"exp":"지각동사(hear)+목적어+V-ing(진행 중인 동작)","section":"문법"},{"type":"도치","q":"Only then _____ the true extent of the damage.","opts":["they realized","did they realize","they did realize","realized they"],"ans":1,"exp":"Only+부사 문두 → 조동사+주어 도치","section":"문법"},{"type":"관계부사","q":"The protocol explains the reason _____ all aerial operations were suspended.","opts":["which","that","why","for which"],"ans":2,"exp":"reason+why = 이유 관계부사(= for which)","section":"문법"},{"type":"도치","q":"Not until the building was secured _____ allowed to enter.","opts":["the crew was","was the crew","the crew is","is the crew"],"ans":1,"exp":"부정어(Not until) 문두 → 주어·동사 도치","section":"문법"},{"type":"가정법-wish","q":"I wish the department _____ adopted the new protocol earlier.","opts":["has","had","would have","will have"],"ans":1,"exp":"wish+가정법 과거완료: wish+주어+had p.p. → 과거 사실 반대","section":"문법"},{"part":1,"q":"[Part 1] \"Are there any exposures we need to protect?\"\n\"The east wall is about fifteen feet from an occupied residential building.\"\n\nQ: 노출 위험 건물의 위치는?","opts":["서쪽 15피트","동쪽 15피트","북쪽 20피트","남쪽 10피트"],"ans":1,"exp":"'east wall ... fifteen feet from residential building'","section":"청취"},{"part":1,"q":"[Part 1] \"Is the water supply adequate for a prolonged operation?\"\n\"We've got two hydrants on Oak and Main — should be sufficient.\"\n\nQ: 사용 가능한 소화전 수는?","opts":["1개","2개","3개","4개"],"ans":1,"exp":"'two hydrants on Oak and Main'","section":"청취"},{"part":1,"q":"[Part 1] \"How many civilians were displaced by the fire?\"\n\"Forty-three. The Red Cross has set up a shelter at the community center.\"\n\nQ: 이재민 수용 장소는?","opts":["학교","소방서","지역 센터","호텔"],"ans":2,"exp":"'Red Cross ... shelter at the community center'","section":"청취"},{"part":1,"q":"[Part 1] \"Did all personnel make it out of the collapse zone?\"\n\"All accounted for — PAR was clear.\"\n\nQ: 붕괴 구역 인원 현황은?","opts":["1명 행방불명","전원 확인 완료","2명 부상","PAR 미실시"],"ans":1,"exp":"'All accounted for — PAR was clear'","section":"청취"},{"part":1,"q":"[Part 1] \"Did the building owner provide access to the utility room?\"\n\"Eventually — took about twenty minutes of negotiation.\"\n\nQ: 다용도실 접근은?","opts":["즉시 허용","약 20분 협상 후 허용","거부됨","경찰이 강제 진입"],"ans":1,"exp":"'took about twenty minutes of negotiation'","section":"청취"},{"part":1,"q":"[Part 1] \"Has the gas been shut off?\"\n\"The utility company confirmed it was isolated at 0312.\"\n\nQ: 가스 차단 시간은?","opts":["0212","0312","0412","0512"],"ans":1,"exp":"'isolated at 0312'","section":"청취"},{"part":1,"q":"[Part 1] \"Is the incident commander still on scene?\"\n\"He handed off to Battalion Chief Park about an hour ago.\"\n\nQ: 현재 사고지휘관은?","opts":["원래 지휘관","Park 대대장","부서장","훈련 지휘관"],"ans":1,"exp":"'handed off to Battalion Chief Park'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"When should we hold the press conference?\"\n\"Let's aim for Thursday — that gives us two days to compile the full timeline and coordinate with the mayor's office.\"\n\nQ: 기자회견 예정일은?","opts":["화요일","수요일","목요일","금요일"],"ans":2,"exp":"'aim for Thursday'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The thermal camera flagged a hot spot on the east wall during overhaul.\"\n\"Did the crew investigate it?\"\n\"Yes — they opened up about four feet of wall and found smoldering insulation. It was extinguished, but it could have rekindled overnight.\"\n\nQ: 동쪽 벽에서 발견된 것은?","opts":["가스관 손상","훈소하는 단열재","전기 화재 흔적","구조적 손상"],"ans":1,"exp":"'smoldering insulation'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"Good catch. Make sure overhaul protocols include mandatory thermal imaging of adjacent walls going forward.\"\n\"Already drafting the SOG update. I'll have it ready by next shift.\"\n\nQ: SOG 업데이트 완료 예정 시점은?","opts":["오늘 중","다음 교대 전","다음 주","한 달 이내"],"ans":1,"exp":"'ready by next shift'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The community is demanding a public explanation for the response delay.\"\n\"I understand. We need to be transparent. Let's schedule a press conference and walk them through the timeline.\"\n\"Should we involve legal counsel?\"\n\"Yes — standard procedure for any incident that draws this level of scrutiny.\"\n\nQ: 대응 지연에 대한 결정된 조치는?","opts":["언론 보도 차단","법적 대응 거부","기자회견 개최 및 타임라인 공개","관계자 즉시 징계"],"ans":2,"exp":"'schedule a press conference and walk them through the timeline'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The post-incident analysis showed three critical decision points where the outcome could have been different.\"\n\"Which ones?\"\n\"Entry timing, ventilation coordination, and RIT positioning. If any one of those had gone differently, we might have had a mayday.\"\n\nQ: 분석에서 밝혀진 결정적 실수 수는?","opts":["1가지","2가지","3가지","4가지"],"ans":2,"exp":"'three critical decision points'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"What's the main takeaway from this incident?\"\n\"Coordination between ventilation and attack teams needs to be tighter. We'll add that to the drill curriculum.\"\n\nQ: 주요 개선 사항은?","opts":["RIT 배치 변경","환기-진압 팀 조율 강화","진입 시점 교정","MAYDAY 절차 수정"],"ans":1,"exp":"'Coordination between ventilation and attack teams needs to be tighter'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Following last month's near-miss incident, all engine companies will participate in a mandatory hose load refresher. The training will be conducted in three sessions this week: Tuesday, Wednesday, and Friday. All company officers must sign attendance sheets and submit them to training by end of day Friday.\"\n\nQ: 출석 명단 제출 마감은?","opts":["화요일 종례","수요일 종례","금요일 종례","다음 주 월요일"],"ans":2,"exp":"'submit them to training by end of day Friday'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"A reminder that all annual SCBA fit tests must be completed before the end of the quarter. If you have not yet scheduled yours, contact the equipment coordinator immediately. Personnel who fail to complete the test will be placed on restricted duty until compliance is achieved.\"\n\nQ: 적합성 시험 미완료 시 결과는?","opts":["급여 삭감","징계 처분","제한 근무 배치","즉시 휴직"],"ans":2,"exp":"'placed on restricted duty until compliance is achieved'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"The new Personnel Accountability System goes live on the first of next month. Every firefighter will be issued a new accountability tag embedded with an RFID chip. These replace the old dog-tag system. Failure to carry your tag while on duty will result in a written warning on first offense, and suspension on the second.\"\n\nQ: 태그 미소지 시 두 번째 위반 처벌은?","opts":["구두 경고","서면 경고","정직","해임"],"ans":2,"exp":"'suspension on the second'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"The department will be conducting a multi-agency disaster drill on the 18th. Participating agencies include fire, EMS, law enforcement, and public works. All personnel should be in uniform and report to the staging area at 0700. Observers from city hall will be present, so professionalism is expected.\"\n\nQ: 훈련에 참여하지 않는 기관은?","opts":["소방","의료","법 집행","공중 보건"],"ans":3,"exp":"public works(공공 작업)가 있지만 공중 보건(public health)은 언급되지 않음","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Effective immediately, all incident commanders must submit a written size-up report within 30 minutes of arrival at any working structure fire. The report must include: life safety status, fire conditions, building construction type, and resource needs. Forms are available in the command vehicle.\"\n\nQ: 30분 이내 보고서에 포함해야 할 항목이 아닌 것은?","opts":["인명 안전 현황","화재 조건","건물 구조 유형","화재 원인 추정"],"ans":3,"exp":"화재 원인 추정은 언급된 4개 항목에 없음","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Tonight's scene involves a suspected natural gas leak in a residential neighborhood. Evacuate a two-block radius. No motorized vehicles, open flames, or electrical operation within that zone. Once the utility company confirms isolation, ventilate the affected structures before allowing any re-entry.\"\n\nQ: 가스 차단 확인 후 재진입 전 해야 할 것은?","opts":["구조물 사진 촬영","인근 건물 수색","영향받은 구조물 환기","전기 공급 복구"],"ans":2,"exp":"'ventilate the affected structures before allowing any re-entry'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Today we examine building construction types and their fire behavior implications. Type I — fire resistive — uses non-combustible materials and typically withstands fire longest. Type V — wood frame — is the most common in residential construction and presents the greatest collapse risk due to rapid heat damage to structural members.\"\n\nQ: 화재 시 붕괴 위험이 가장 높은 건물 유형은?","opts":["Type I (내화)","Type II (비연소)","Type IV (중목재)","Type V (목조)"],"ans":3,"exp":"'Type V — wood frame ... greatest collapse risk'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Decision-making under stress follows two primary models: the classical analytical model, which evaluates multiple options systematically, and the Recognition-Primed Decision (RPD) model, developed by Gary Klein. RPD describes how experienced decision-makers use pattern recognition to rapidly identify a workable solution without comparing alternatives.\"\n\nQ: RPD 모델의 핵심 특징은?","opts":["모든 선택지 체계적 분석","패턴 인식으로 빠르게 실행 가능한 해결책 식별","팀 합의를 통한 결정","데이터 기반 의사결정"],"ans":1,"exp":"'pattern recognition to rapidly identify a workable solution without comparing alternatives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Accountability at the fireground operates on three levels: individual accountability, where each firefighter knows their assignment; company accountability, where officers track their crew; and command accountability, where IC maintains situational awareness of all resources.\"\n\nQ: 지휘 책임(command accountability)의 핵심은?","opts":["개인 임무 파악","팀 추적","IC의 전체 자원 상황인식 유지","문서 작성"],"ans":2,"exp":"'IC maintains situational awareness of all resources'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"The Phoenix Model of risk management — developed by the Phoenix Fire Department — states: risk a lot to save a savable life, risk a little to save savable property, and risk nothing to save what is already lost. This model has been widely adopted internationally.\"\n\nQ: Phoenix 모델에서 '이미 잃은 것을 구하기 위해' 감수해야 할 위험은?","opts":["최대한","약간","없음","상황에 따라"],"ans":2,"exp":"'risk nothing to save what is already lost'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"Klein's research found that experienced firefighters rarely compare multiple options. Instead, they mentally simulate the chosen course of action to check for obvious flaws, then act. This mental simulation — 'if I do this, what happens?' — is a key feature of expert decision-making.\"\n\nQ: 숙련된 소방관의 의사결정에서 '정신적 시뮬레이션'의 역할은?","opts":["선택지 수를 늘림","선택된 행동 과정의 명백한 결함 확인","팀 전체에 결정 전달","문서 작성"],"ans":1,"exp":"'mentally simulate ... to check for obvious flaws'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"A Personnel Accountability Report (PAR) is a roll call of all assigned personnel at defined intervals or triggered by significant events — a MAYDAY, sudden change in fire conditions, or transition from offensive to defensive operations.\"\n\nQ: PAR 실시를 트리거하는 사건이 아닌 것은?","opts":["MAYDAY 발령","화재 상황 급변","공세→수세 전환","정기 교대 시간"],"ans":3,"exp":"정기 교대 시간은 PAR 트리거로 언급되지 않음","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"Type III construction — ordinary construction — combines non-combustible exterior walls with combustible interior framing. The void spaces within these walls allow fire to travel vertically unseen, a phenomenon known as balloon frame fire spread.\"\n\nQ: Type III 건물에서 화재가 눈에 보이지 않게 수직으로 확산하는 이유는?","opts":["알루미늄 외벽","벽 내 빈 공간","스프링클러 부재","목재 바닥"],"ans":1,"exp":"'void spaces within these walls allow fire to travel vertically unseen'","section":"청취"},{"q":"\"Mayday procedures require: announcing MAYDAY three times, stating name and unit, describing the emergency, and providing location. The IC assigns a dedicated channel and activates the RIT.\"\n\nQ: MAYDAY 선언 시 가장 먼저 해야 하는 것은?","opts":["위치 알리기","MAYDAY 세 번 반복","RIT 가동","채널 변경"],"ans":1,"exp":"'announcing MAYDAY three times' → 가장 먼저 세 번 반복","section":"독해","passage":"X"},{"q":"Q: 지문에서 'congestion'의 의미는?","opts":["danger","overcrowding/blockage","noise","delay"],"ans":1,"exp":"congestion = 혼잡, 밀집(overcrowding)","section":"독해","passage":"X"},{"q":"\"Water curtains can be used to protect exposures from radiant heat during large fires. They create a water barrier between the burning structure and adjacent buildings.\"\n\nQ: 수막(water curtain)의 용도는?","opts":["화재 직접 진압","복사열로부터 인접 건물 보호","시야 확보","연기 제거"],"ans":1,"exp":"'protect exposures from radiant heat'","section":"독해","passage":"X"},{"q":"\"Incident size-up is a continuous process that begins before arrival and continues throughout the incident. Key factors include: building construction, occupancy, life safety, fire extension, and available resources.\"\n\nQ: 상황평가(size-up)는 언제 시작하는가?","opts":["현장 도착 후","내부 진입 후","도착 전부터 지속적으로","지휘소 설치 후"],"ans":2,"exp":"'begins before arrival and continues throughout'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'salvage'의 의미는?","opts":["destruction","property protection after disaster","fire suppression","evacuation"],"ans":1,"exp":"salvage = 화재 후 재산 보호 작업","section":"독해","passage":"X"},{"q":"\"Unified command is appropriate when an incident involves multiple jurisdictions or agencies with overlapping responsibilities. Each agency retains its own authority while contributing to a single Incident Action Plan.\"\n\nQ: 통합지휘가 적합한 상황은?","opts":["단일 기관 소규모 사고","다관할·다기관 중복 책임 사고","야간 단독 사고","훈련 중"],"ans":1,"exp":"'multiple jurisdictions or agencies with overlapping responsibilities'","section":"독해","passage":"X"},{"q":"\"Overhaul is the systematic process of searching the fire scene for hidden hot spots after the main fire is controlled. Thermal imaging cameras significantly enhance overhaul efficiency.\"\n\nQ: 잔화처리 중 열화상 카메라의 역할은?","opts":["화재 원인 조사","숨겨진 열점 탐지 효율 향상","통신 지원","건물 구조 분석"],"ans":1,"exp":"'Thermal imaging cameras significantly enhance overhaul efficiency'","section":"독해","passage":"X"},{"q":"\"Conflagrations — large fires that spread beyond their point of origin to involve multiple structures — require regional mutual aid and can overwhelm local resources. Historic conflagrations often reshape building codes and fire prevention strategies.\"\n\nQ: 대규모 화재(conflagration)의 장기적 영향은?","opts":["일시적 혼란","건축 법규·방화 전략 재편","보험 비용 감소","지역 경제 성장"],"ans":1,"exp":"'reshape building codes and fire prevention strategies'","section":"독해","passage":"X"},{"q":"\"Ground monitors — large-caliber nozzles positioned without requiring a firefighter to hold them — are used in defensive operations to deliver high-volume streams.\"\n\nQ: 지상 모니터의 주요 장점은?","opts":["높은 정밀도","소방관 없이 고용량 방수 가능","실내 전용","이동성"],"ans":1,"exp":"'without requiring a firefighter to hold them'","section":"독해","passage":"X"},{"q":"\"Preplanning visits allow fire crews to familiarize themselves with building layouts, hazards, utility shutoffs, and occupancy loads. Buildings with completed preplans consistently show better outcomes during actual incidents.\"\n\nQ: 사전 계획 방문의 이점은?","opts":["건물 소유자와 관계 형성","대응 효과 향상","법적 면책","건물 코드 검사"],"ans":1,"exp":"'better outcomes during actual incidents'","section":"독해","passage":"X"},{"q":"\"The incident action plan (IAP) is updated each operational period to reflect changing conditions. It documents objectives, strategies, tactics, and resource assignments.\"\n\nQ: IAP가 업데이트되는 시점은?","opts":["사고 시작 시 한 번","매 작전 기간마다","48시간마다","사고 종료 후"],"ans":1,"exp":"'updated each operational period'","section":"독해","passage":"X"},{"q":"\"The staging area is a designated location where resources are assembled and await assignment. It is separate from the operational area to reduce congestion and improve coordination.\"\n\nQ: 대기 구역(staging area)이 작전 구역과 분리되는 이유는?","opts":["보안 유지","혼잡 감소 및 조율 향상","비용 절감","법적 요건"],"ans":1,"exp":"'reduce congestion and improve coordination'","section":"독해","passage":"X"},{"q":"\"Breathing air cylinders for SCBA must be hydrostatically tested every five years. Any cylinder showing corrosion, dents, or damage to the neck threads must be removed from service immediately.\"\n\nQ: SCBA 실린더를 즉시 사용 중단해야 하는 조건은?","opts":["5년 미경과","사용 횟수 초과","부식·움푹 팬 곳·목 나사산 손상","압력 약간 감소"],"ans":2,"exp":"'corrosion, dents, or damage to the neck threads'","section":"독해","passage":"X"},{"q":"\"Salvage operations protect property from water, smoke, and overhaul damage after the main fire is controlled. Covers, mops, and squeegees are essential salvage tools.\"\n\nQ: 잔화처리(salvage) 작업의 주요 목적은?","opts":["잔불 제거","수색 실시","추가 피해로부터 재산 보호","화재 원인 조사"],"ans":2,"exp":"'protect property from water, smoke, and overhaul damage'","section":"독해","passage":"X"},{"q":"\"Firefighter fatalities from cardiac events account for nearly 45% of line-of-duty deaths annually. Regular cardiovascular fitness assessments and mandatory medical evaluations are now standard in most departments.\"\n\nQ: 심장 관련 사망이 전체의 몇 퍼센트를 차지하는가?","opts":["약 25%","약 35%","약 45%","약 55%"],"ans":2,"exp":"'nearly 45% of line-of-duty deaths'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'occupancy loads'의 의미는?","opts":["weight limits","number of people in a building","utility capacity","fire load"],"ans":1,"exp":"occupancy load = 건물 재실 인원 수","section":"독해","passage":"X"},{"q":"Q: 지문에서 'systematic'의 의미는?","opts":["random","methodical/organized","rapid","minimal"],"ans":1,"exp":"systematic = 체계적인(methodical/organized)","section":"독해","passage":"X"},{"q":"Q: 지문에서 'formalized'의 의미는?","opts":["ignored","made official/structured","challenged","simplified"],"ans":1,"exp":"formalized = 공식화했다(made official)","section":"독해","passage":"EX"},{"q":"\"Risk a nothing to save nothing' applies when there is no potential for life safety — for example, when a structure is fully involved and confirmed unoccupied. In such cases, defensive operations protect firefighters.\"\n\nQ: '아무것도 걸지 않는다' 원칙을 적용하는 상황은?","opts":["생존자 확인 시","구조물이 완전 연소되고 비어있음이 확인된 때","소형 화재","야간 작전"],"ans":1,"exp":"'when structure is fully involved and confirmed unoccupied'","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'pioneered'의 의미는?","opts":["criticized","followed","developed/led the way","rejected"],"ans":2,"exp":"pioneered = 선구적으로 개척했다","section":"독해","passage":"EX"},{"q":"\"THINCS identifies eight key NTS domains: situational awareness, decision-making, communication, leadership, teamwork, task management, stress management, and adaptability.\"\n\nQ: THINCS의 NTS 8개 영역이 아닌 것은?","opts":["상황인식","장비 조작","스트레스 관리","적응력"],"ans":1,"exp":"장비 조작(equipment operation)은 NTS가 아닌 기술적 역량","section":"독해","passage":"EX"},{"q":"\"The Phoenix Fire Department pioneered the 'risk a lot to save a lot, risk a little to save a little, risk nothing to save nothing' doctrine. This framework guides commanders in calibrating risk levels based on what can be gained.\"\n\nQ: 이 원칙이 지휘관에게 제공하는 것은?","opts":["엄격한 절차","상황별 위험 조율 기준","새 장비 지침","법적 근거"],"ans":1,"exp":"'guides commanders in calibrating risk levels based on what can be gained'","section":"독해","passage":"EX"},{"q":"\"FIRESCOPE established common terminology, unified command, and modular organization — concepts that became the foundation of ICS and later NIMS.\"\n\nQ: FIRESCOPE가 확립한 개념이 아닌 것은?","opts":["공통 용어","통합 지휘","모듈 조직","드론 운용"],"ans":3,"exp":"드론 운용은 FIRESCOPE 당시(1970년대) 개념이 아님","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'integrates'의 의미는?","opts":["separates","combines into one","evaluates","removes"],"ans":1,"exp":"integrates = 통합하다(combines into one)","section":"독해","passage":"EX"},{"q":"\"FIRESCOPE (Firefighting Resources of Southern California Organized for Potential Emergencies) was the collaborative effort that formalized ICS. It emerged from lessons learned during the 1970 Laguna and Claremont fires.\"\n\nQ: FIRESCOPE의 기원이 된 사건은?","opts":["1980년대 허리케인","1970년 Laguna·Claremont 산불","9/11 테러","1990년대 홍수"],"ans":1,"exp":"'emerged from lessons learned during the 1970 Laguna and Claremont fires'","section":"독해","passage":"EX"},{"q":"\"The incident commander is responsible for the overall management of the incident. This includes establishing objectives, ordering resources, and ensuring the safety of all personnel.\"\n\nQ: 사고지휘관의 책임이 아닌 것은?","opts":["목표 수립","자원 요청","전체 관리","개인 소방 장비 점검"],"ans":3,"exp":"개인 장비 점검은 개인 책임, 지휘관 직무 아님","section":"독해","passage":"Y"},{"q":"\"Fire flow is the quantity of water required for fire suppression, expressed in gallons per minute (gpm). It depends on building size, construction type, and fire load.\"\n\nQ: 지문에서 'fire flow'에 영향을 주는 요소가 아닌 것은?","opts":["건물 크기","건물 구조 유형","화재 부하","기상 조건"],"ans":3,"exp":"기상 조건은 fire flow 결정 요소로 언급되지 않음","section":"독해","passage":"Y"},{"q":"Q: 지문에서 'suppression'의 의미는?","opts":["ignition","extinguishment/control","spread","detection"],"ans":1,"exp":"fire suppression = 화재 진압·통제(extinguishment/control)","section":"독해","passage":"Y"}]},{"round":4,"title":"제4회 기출 유형","analysis":{"summary":"사역·지각동사 구문, 비교급, 병렬 구조, 부정사 관용구. 청취 현장 보고·교육 공지, 독해 Phoenix 위험관리·FIRESCOPE 지문.","tips":["사역동사(make/have/let)+목적어+동사원형","지각동사(see/hear/watch)+목적어+동사원형 또는 V-ing","병렬: A, B, and C → 같은 품사·형태"]},"qs":[{"type":"현재완료","q":"The unit _____ on standby since 0600.","opts":["is","was","has been","had been"],"ans":2,"exp":"since+시점 → 현재완료(has been)","section":"문법"},{"type":"과거완료","q":"The evacuation _____ completed before the structure collapsed.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거(collapsed) → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"가정법 과거","q":"If the equipment _____ in better condition, the task would be easier.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"가정법 과거완료","q":"If the team _____ the warning, the firefighter would not have been injured.","opts":["heeded","heeds","had heeded","has heeded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., would have p.p.","section":"문법"},{"type":"준동사-동명사","q":"The chief recommended _____ all rooftop access points before committing crews.","opts":["to assess","assess","assessing","assessed"],"ans":2,"exp":"recommend+동명사(V-ing)","section":"문법"},{"type":"준동사-to부정사","q":"The department agreed _____ the new accountability system by January.","opts":["implement","implementing","to implement","implemented"],"ans":2,"exp":"agree+to부정사","section":"문법"},{"type":"관계사-who","q":"The medic _____ treated the burn victims received a commendation.","opts":["who","which","whose","whom"],"ans":0,"exp":"사람 선행사+주어 역할 → who","section":"문법"},{"type":"관계사-whose","q":"The officer _____ unit responded first was praised for the fastest deployment.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"조동사-must","q":"The radio must _____ malfunctioned — no transmissions were received.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측","section":"문법"},{"type":"조동사-should","q":"The crew should _____ performed a 360-degree walkthrough before entry.","opts":["have","had","be","has"],"ans":0,"exp":"should have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"수동태","q":"The incident report _____ finalized before the press briefing.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"미래완료","q":"By next Tuesday, the department _____ its centennial celebrations.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by+미래시점 → 미래완료(will have p.p.)","section":"문법"},{"type":"분사구문","q":"The alarm _____ at midnight, all off-duty personnel were immediately recalled.","opts":["sounding","having sounded","sounded","to sound"],"ans":1,"exp":"Having p.p. = 경보가 울린 후 → 수동 분사구문","section":"문법"},{"type":"강조구문","q":"It was the outdated equipment _____ caused the malfunction.","opts":["which","that","who","what"],"ans":1,"exp":"강조구문(It is ... that): It was X that Y → that 고정","section":"문법"},{"type":"부정사 구문","q":"The regulation requires all units _____ before entering IDLH environments.","opts":["check","checking","to check","checked"],"ans":2,"exp":"require+목적어+to부정사: requires A to V","section":"문법"},{"type":"준동사-지각동사","q":"The supervisor heard the team _____ the evacuation alarm.","opts":["to activate","activating","activated","activation"],"ans":1,"exp":"지각동사(hear)+목적어+V-ing(진행 중인 동작)","section":"문법"},{"type":"간접의문문","q":"Could you tell me _____ the drill starts?","opts":["when does","when","what time does","that when"],"ans":1,"exp":"간접의문문: 의문사+주어+동사(정상 어순)","section":"문법"},{"type":"관계부사","q":"The protocol explains the reason _____ all aerial operations were suspended.","opts":["which","that","why","for which"],"ans":2,"exp":"reason+why = 이유 관계부사(= for which)","section":"문법"},{"type":"가정법-wish","q":"I wish the department _____ adopted the new protocol earlier.","opts":["has","had","would have","will have"],"ans":1,"exp":"wish+가정법 과거완료: wish+주어+had p.p. → 과거 사실 반대","section":"문법"},{"type":"도치","q":"Not until the building was secured _____ allowed to enter.","opts":["the crew was","was the crew","the crew is","is the crew"],"ans":1,"exp":"부정어(Not until) 문두 → 주어·동사 도치","section":"문법"},{"type":"간접의문문","q":"The chief asked _____ the new recruits had passed their fitness test.","opts":["that whether","if","whether that","that"],"ans":1,"exp":"간접의문문: asked if/whether+주어+동사","section":"문법"},{"type":"준동사-사역동사","q":"The chief had the recruits _____ the drill twice.","opts":["repeat","to repeat","repeating","repeated"],"ans":0,"exp":"사역동사(have)+목적어+동사원형","section":"문법"},{"type":"가정법-wish","q":"The firefighter wishes she _____ more time to practice the drill.","opts":["has","had","would have","will have"],"ans":1,"exp":"wish+가정법 과거: wish+주어+had → 현재 사실 반대","section":"문법"},{"type":"복합 시제","q":"By the time you read this report, the investigation _____ for a week.","opts":["will run","will be running","will have been running","runs"],"ans":2,"exp":"by the time+현재 → 미래완료진행(will have been V-ing)","section":"문법"},{"type":"복합 관계사","q":"The commander approved _____ the safety officer recommended.","opts":["that","which","what","who"],"ans":2,"exp":"선행사 없는 명사절 목적어 → what(~하는 것을)","section":"문법"},{"type":"분사구문","q":"_____ all exits, the safety team confirmed the building was clear.","opts":["Checking","Having checked","To check","Checked"],"ans":1,"exp":"분사구문: Having p.p. = 주절보다 이전에 완료된 동작","section":"문법"},{"part":1,"q":"[Part 1] \"Is the incident commander still on scene?\"\n\"He handed off to Battalion Chief Park about an hour ago.\"\n\nQ: 현재 사고지휘관은?","opts":["원래 지휘관","Park 대대장","부서장","훈련 지휘관"],"ans":1,"exp":"'handed off to Battalion Chief Park'","section":"청취"},{"part":1,"q":"[Part 1] \"Did all personnel make it out of the collapse zone?\"\n\"All accounted for — PAR was clear.\"\n\nQ: 붕괴 구역 인원 현황은?","opts":["1명 행방불명","전원 확인 완료","2명 부상","PAR 미실시"],"ans":1,"exp":"'All accounted for — PAR was clear'","section":"청취"},{"part":1,"q":"[Part 1] \"Is the water supply adequate for a prolonged operation?\"\n\"We've got two hydrants on Oak and Main — should be sufficient.\"\n\nQ: 사용 가능한 소화전 수는?","opts":["1개","2개","3개","4개"],"ans":1,"exp":"'two hydrants on Oak and Main'","section":"청취"},{"part":1,"q":"[Part 1] \"Did the building owner provide access to the utility room?\"\n\"Eventually — took about twenty minutes of negotiation.\"\n\nQ: 다용도실 접근은?","opts":["즉시 허용","약 20분 협상 후 허용","거부됨","경찰이 강제 진입"],"ans":1,"exp":"'took about twenty minutes of negotiation'","section":"청취"},{"part":1,"q":"[Part 1] \"How many civilians were displaced by the fire?\"\n\"Forty-three. The Red Cross has set up a shelter at the community center.\"\n\nQ: 이재민 수용 장소는?","opts":["학교","소방서","지역 센터","호텔"],"ans":2,"exp":"'Red Cross ... shelter at the community center'","section":"청취"},{"part":1,"q":"[Part 1] \"Has the gas been shut off?\"\n\"The utility company confirmed it was isolated at 0312.\"\n\nQ: 가스 차단 시간은?","opts":["0212","0312","0412","0512"],"ans":1,"exp":"'isolated at 0312'","section":"청취"},{"part":1,"q":"[Part 1] \"Are there any exposures we need to protect?\"\n\"The east wall is about fifteen feet from an occupied residential building.\"\n\nQ: 노출 위험 건물의 위치는?","opts":["서쪽 15피트","동쪽 15피트","북쪽 20피트","남쪽 10피트"],"ans":1,"exp":"'east wall ... fifteen feet from residential building'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"Good catch. Make sure overhaul protocols include mandatory thermal imaging of adjacent walls going forward.\"\n\"Already drafting the SOG update. I'll have it ready by next shift.\"\n\nQ: SOG 업데이트 완료 예정 시점은?","opts":["오늘 중","다음 교대 전","다음 주","한 달 이내"],"ans":1,"exp":"'ready by next shift'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"When should we hold the press conference?\"\n\"Let's aim for Thursday — that gives us two days to compile the full timeline and coordinate with the mayor's office.\"\n\nQ: 기자회견 예정일은?","opts":["화요일","수요일","목요일","금요일"],"ans":2,"exp":"'aim for Thursday'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The thermal camera flagged a hot spot on the east wall during overhaul.\"\n\"Did the crew investigate it?\"\n\"Yes — they opened up about four feet of wall and found smoldering insulation. It was extinguished, but it could have rekindled overnight.\"\n\nQ: 동쪽 벽에서 발견된 것은?","opts":["가스관 손상","훈소하는 단열재","전기 화재 흔적","구조적 손상"],"ans":1,"exp":"'smoldering insulation'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The community is demanding a public explanation for the response delay.\"\n\"I understand. We need to be transparent. Let's schedule a press conference and walk them through the timeline.\"\n\"Should we involve legal counsel?\"\n\"Yes — standard procedure for any incident that draws this level of scrutiny.\"\n\nQ: 대응 지연에 대한 결정된 조치는?","opts":["언론 보도 차단","법적 대응 거부","기자회견 개최 및 타임라인 공개","관계자 즉시 징계"],"ans":2,"exp":"'schedule a press conference and walk them through the timeline'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The post-incident analysis showed three critical decision points where the outcome could have been different.\"\n\"Which ones?\"\n\"Entry timing, ventilation coordination, and RIT positioning. If any one of those had gone differently, we might have had a mayday.\"\n\nQ: 분석에서 밝혀진 결정적 실수 수는?","opts":["1가지","2가지","3가지","4가지"],"ans":2,"exp":"'three critical decision points'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"What's the main takeaway from this incident?\"\n\"Coordination between ventilation and attack teams needs to be tighter. We'll add that to the drill curriculum.\"\n\nQ: 주요 개선 사항은?","opts":["RIT 배치 변경","환기-진압 팀 조율 강화","진입 시점 교정","MAYDAY 절차 수정"],"ans":1,"exp":"'Coordination between ventilation and attack teams needs to be tighter'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"A reminder that all annual SCBA fit tests must be completed before the end of the quarter. If you have not yet scheduled yours, contact the equipment coordinator immediately. Personnel who fail to complete the test will be placed on restricted duty until compliance is achieved.\"\n\nQ: 적합성 시험 미완료 시 결과는?","opts":["급여 삭감","징계 처분","제한 근무 배치","즉시 휴직"],"ans":2,"exp":"'placed on restricted duty until compliance is achieved'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Following last month's near-miss incident, all engine companies will participate in a mandatory hose load refresher. The training will be conducted in three sessions this week: Tuesday, Wednesday, and Friday. All company officers must sign attendance sheets and submit them to training by end of day Friday.\"\n\nQ: 출석 명단 제출 마감은?","opts":["화요일 종례","수요일 종례","금요일 종례","다음 주 월요일"],"ans":2,"exp":"'submit them to training by end of day Friday'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Tonight's scene involves a suspected natural gas leak in a residential neighborhood. Evacuate a two-block radius. No motorized vehicles, open flames, or electrical operation within that zone. Once the utility company confirms isolation, ventilate the affected structures before allowing any re-entry.\"\n\nQ: 가스 차단 확인 후 재진입 전 해야 할 것은?","opts":["구조물 사진 촬영","인근 건물 수색","영향받은 구조물 환기","전기 공급 복구"],"ans":2,"exp":"'ventilate the affected structures before allowing any re-entry'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Effective immediately, all incident commanders must submit a written size-up report within 30 minutes of arrival at any working structure fire. The report must include: life safety status, fire conditions, building construction type, and resource needs. Forms are available in the command vehicle.\"\n\nQ: 30분 이내 보고서에 포함해야 할 항목이 아닌 것은?","opts":["인명 안전 현황","화재 조건","건물 구조 유형","화재 원인 추정"],"ans":3,"exp":"화재 원인 추정은 언급된 4개 항목에 없음","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"The department will be conducting a multi-agency disaster drill on the 18th. Participating agencies include fire, EMS, law enforcement, and public works. All personnel should be in uniform and report to the staging area at 0700. Observers from city hall will be present, so professionalism is expected.\"\n\nQ: 훈련에 참여하지 않는 기관은?","opts":["소방","의료","법 집행","공중 보건"],"ans":3,"exp":"public works(공공 작업)가 있지만 공중 보건(public health)은 언급되지 않음","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"The new Personnel Accountability System goes live on the first of next month. Every firefighter will be issued a new accountability tag embedded with an RFID chip. These replace the old dog-tag system. Failure to carry your tag while on duty will result in a written warning on first offense, and suspension on the second.\"\n\nQ: 태그 미소지 시 두 번째 위반 처벌은?","opts":["구두 경고","서면 경고","정직","해임"],"ans":2,"exp":"'suspension on the second'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"Klein's research found that experienced firefighters rarely compare multiple options. Instead, they mentally simulate the chosen course of action to check for obvious flaws, then act. This mental simulation — 'if I do this, what happens?' — is a key feature of expert decision-making.\"\n\nQ: 숙련된 소방관의 의사결정에서 '정신적 시뮬레이션'의 역할은?","opts":["선택지 수를 늘림","선택된 행동 과정의 명백한 결함 확인","팀 전체에 결정 전달","문서 작성"],"ans":1,"exp":"'mentally simulate ... to check for obvious flaws'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Today we examine building construction types and their fire behavior implications. Type I — fire resistive — uses non-combustible materials and typically withstands fire longest. Type V — wood frame — is the most common in residential construction and presents the greatest collapse risk due to rapid heat damage to structural members.\"\n\nQ: 화재 시 붕괴 위험이 가장 높은 건물 유형은?","opts":["Type I (내화)","Type II (비연소)","Type IV (중목재)","Type V (목조)"],"ans":3,"exp":"'Type V — wood frame ... greatest collapse risk'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Decision-making under stress follows two primary models: the classical analytical model, which evaluates multiple options systematically, and the Recognition-Primed Decision (RPD) model, developed by Gary Klein. RPD describes how experienced decision-makers use pattern recognition to rapidly identify a workable solution without comparing alternatives.\"\n\nQ: RPD 모델의 핵심 특징은?","opts":["모든 선택지 체계적 분석","패턴 인식으로 빠르게 실행 가능한 해결책 식별","팀 합의를 통한 결정","데이터 기반 의사결정"],"ans":1,"exp":"'pattern recognition to rapidly identify a workable solution without comparing alternatives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"Type III construction — ordinary construction — combines non-combustible exterior walls with combustible interior framing. The void spaces within these walls allow fire to travel vertically unseen, a phenomenon known as balloon frame fire spread.\"\n\nQ: Type III 건물에서 화재가 눈에 보이지 않게 수직으로 확산하는 이유는?","opts":["알루미늄 외벽","벽 내 빈 공간","스프링클러 부재","목재 바닥"],"ans":1,"exp":"'void spaces within these walls allow fire to travel vertically unseen'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Accountability at the fireground operates on three levels: individual accountability, where each firefighter knows their assignment; company accountability, where officers track their crew; and command accountability, where IC maintains situational awareness of all resources.\"\n\nQ: 지휘 책임(command accountability)의 핵심은?","opts":["개인 임무 파악","팀 추적","IC의 전체 자원 상황인식 유지","문서 작성"],"ans":2,"exp":"'IC maintains situational awareness of all resources'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"A Personnel Accountability Report (PAR) is a roll call of all assigned personnel at defined intervals or triggered by significant events — a MAYDAY, sudden change in fire conditions, or transition from offensive to defensive operations.\"\n\nQ: PAR 실시를 트리거하는 사건이 아닌 것은?","opts":["MAYDAY 발령","화재 상황 급변","공세→수세 전환","정기 교대 시간"],"ans":3,"exp":"정기 교대 시간은 PAR 트리거로 언급되지 않음","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"The Phoenix Model of risk management — developed by the Phoenix Fire Department — states: risk a lot to save a savable life, risk a little to save savable property, and risk nothing to save what is already lost. This model has been widely adopted internationally.\"\n\nQ: Phoenix 모델에서 '이미 잃은 것을 구하기 위해' 감수해야 할 위험은?","opts":["최대한","약간","없음","상황에 따라"],"ans":2,"exp":"'risk nothing to save what is already lost'","section":"청취"},{"q":"\"Unified command is appropriate when an incident involves multiple jurisdictions or agencies with overlapping responsibilities. Each agency retains its own authority while contributing to a single Incident Action Plan.\"\n\nQ: 통합지휘가 적합한 상황은?","opts":["단일 기관 소규모 사고","다관할·다기관 중복 책임 사고","야간 단독 사고","훈련 중"],"ans":1,"exp":"'multiple jurisdictions or agencies with overlapping responsibilities'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'congestion'의 의미는?","opts":["danger","overcrowding/blockage","noise","delay"],"ans":1,"exp":"congestion = 혼잡, 밀집(overcrowding)","section":"독해","passage":"X"},{"q":"\"Salvage operations protect property from water, smoke, and overhaul damage after the main fire is controlled. Covers, mops, and squeegees are essential salvage tools.\"\n\nQ: 잔화처리(salvage) 작업의 주요 목적은?","opts":["잔불 제거","수색 실시","추가 피해로부터 재산 보호","화재 원인 조사"],"ans":2,"exp":"'protect property from water, smoke, and overhaul damage'","section":"독해","passage":"X"},{"q":"\"Conflagrations — large fires that spread beyond their point of origin to involve multiple structures — require regional mutual aid and can overwhelm local resources. Historic conflagrations often reshape building codes and fire prevention strategies.\"\n\nQ: 대규모 화재(conflagration)의 장기적 영향은?","opts":["일시적 혼란","건축 법규·방화 전략 재편","보험 비용 감소","지역 경제 성장"],"ans":1,"exp":"'reshape building codes and fire prevention strategies'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'systematic'의 의미는?","opts":["random","methodical/organized","rapid","minimal"],"ans":1,"exp":"systematic = 체계적인(methodical/organized)","section":"독해","passage":"X"},{"q":"\"Incident size-up is a continuous process that begins before arrival and continues throughout the incident. Key factors include: building construction, occupancy, life safety, fire extension, and available resources.\"\n\nQ: 상황평가(size-up)는 언제 시작하는가?","opts":["현장 도착 후","내부 진입 후","도착 전부터 지속적으로","지휘소 설치 후"],"ans":2,"exp":"'begins before arrival and continues throughout'","section":"독해","passage":"X"},{"q":"\"Water curtains can be used to protect exposures from radiant heat during large fires. They create a water barrier between the burning structure and adjacent buildings.\"\n\nQ: 수막(water curtain)의 용도는?","opts":["화재 직접 진압","복사열로부터 인접 건물 보호","시야 확보","연기 제거"],"ans":1,"exp":"'protect exposures from radiant heat'","section":"독해","passage":"X"},{"q":"\"Ground monitors — large-caliber nozzles positioned without requiring a firefighter to hold them — are used in defensive operations to deliver high-volume streams.\"\n\nQ: 지상 모니터의 주요 장점은?","opts":["높은 정밀도","소방관 없이 고용량 방수 가능","실내 전용","이동성"],"ans":1,"exp":"'without requiring a firefighter to hold them'","section":"독해","passage":"X"},{"q":"\"The incident action plan (IAP) is updated each operational period to reflect changing conditions. It documents objectives, strategies, tactics, and resource assignments.\"\n\nQ: IAP가 업데이트되는 시점은?","opts":["사고 시작 시 한 번","매 작전 기간마다","48시간마다","사고 종료 후"],"ans":1,"exp":"'updated each operational period'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'occupancy loads'의 의미는?","opts":["weight limits","number of people in a building","utility capacity","fire load"],"ans":1,"exp":"occupancy load = 건물 재실 인원 수","section":"독해","passage":"X"},{"q":"\"Firefighter fatalities from cardiac events account for nearly 45% of line-of-duty deaths annually. Regular cardiovascular fitness assessments and mandatory medical evaluations are now standard in most departments.\"\n\nQ: 심장 관련 사망이 전체의 몇 퍼센트를 차지하는가?","opts":["약 25%","약 35%","약 45%","약 55%"],"ans":2,"exp":"'nearly 45% of line-of-duty deaths'","section":"독해","passage":"X"},{"q":"\"Breathing air cylinders for SCBA must be hydrostatically tested every five years. Any cylinder showing corrosion, dents, or damage to the neck threads must be removed from service immediately.\"\n\nQ: SCBA 실린더를 즉시 사용 중단해야 하는 조건은?","opts":["5년 미경과","사용 횟수 초과","부식·움푹 팬 곳·목 나사산 손상","압력 약간 감소"],"ans":2,"exp":"'corrosion, dents, or damage to the neck threads'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'salvage'의 의미는?","opts":["destruction","property protection after disaster","fire suppression","evacuation"],"ans":1,"exp":"salvage = 화재 후 재산 보호 작업","section":"독해","passage":"X"},{"q":"\"Overhaul is the systematic process of searching the fire scene for hidden hot spots after the main fire is controlled. Thermal imaging cameras significantly enhance overhaul efficiency.\"\n\nQ: 잔화처리 중 열화상 카메라의 역할은?","opts":["화재 원인 조사","숨겨진 열점 탐지 효율 향상","통신 지원","건물 구조 분석"],"ans":1,"exp":"'Thermal imaging cameras significantly enhance overhaul efficiency'","section":"독해","passage":"X"},{"q":"\"The staging area is a designated location where resources are assembled and await assignment. It is separate from the operational area to reduce congestion and improve coordination.\"\n\nQ: 대기 구역(staging area)이 작전 구역과 분리되는 이유는?","opts":["보안 유지","혼잡 감소 및 조율 향상","비용 절감","법적 요건"],"ans":1,"exp":"'reduce congestion and improve coordination'","section":"독해","passage":"X"},{"q":"\"Mayday procedures require: announcing MAYDAY three times, stating name and unit, describing the emergency, and providing location. The IC assigns a dedicated channel and activates the RIT.\"\n\nQ: MAYDAY 선언 시 가장 먼저 해야 하는 것은?","opts":["위치 알리기","MAYDAY 세 번 반복","RIT 가동","채널 변경"],"ans":1,"exp":"'announcing MAYDAY three times' → 가장 먼저 세 번 반복","section":"독해","passage":"X"},{"q":"\"Preplanning visits allow fire crews to familiarize themselves with building layouts, hazards, utility shutoffs, and occupancy loads. Buildings with completed preplans consistently show better outcomes during actual incidents.\"\n\nQ: 사전 계획 방문의 이점은?","opts":["건물 소유자와 관계 형성","대응 효과 향상","법적 면책","건물 코드 검사"],"ans":1,"exp":"'better outcomes during actual incidents'","section":"독해","passage":"X"},{"q":"\"The UK THINCS model (Tactical, Human, Incident, Non-technical Command Skills) integrates technical and non-technical competencies into a single framework for evaluating incident commanders.\"\n\nQ: THINCS 모델의 특징은?","opts":["기술 역량만 평가","기술·비기술 역량 통합 평가","인원 관리 전용","장비 평가 도구"],"ans":1,"exp":"'integrates technical and non-technical competencies'","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'pioneered'의 의미는?","opts":["criticized","followed","developed/led the way","rejected"],"ans":2,"exp":"pioneered = 선구적으로 개척했다","section":"독해","passage":"EX"},{"q":"\"FIRESCOPE (Firefighting Resources of Southern California Organized for Potential Emergencies) was the collaborative effort that formalized ICS. It emerged from lessons learned during the 1970 Laguna and Claremont fires.\"\n\nQ: FIRESCOPE의 기원이 된 사건은?","opts":["1980년대 허리케인","1970년 Laguna·Claremont 산불","9/11 테러","1990년대 홍수"],"ans":1,"exp":"'emerged from lessons learned during the 1970 Laguna and Claremont fires'","section":"독해","passage":"EX"},{"q":"\"FIRESCOPE established common terminology, unified command, and modular organization — concepts that became the foundation of ICS and later NIMS.\"\n\nQ: FIRESCOPE가 확립한 개념이 아닌 것은?","opts":["공통 용어","통합 지휘","모듈 조직","드론 운용"],"ans":3,"exp":"드론 운용은 FIRESCOPE 당시(1970년대) 개념이 아님","section":"독해","passage":"EX"},{"q":"\"The Phoenix Fire Department pioneered the 'risk a lot to save a lot, risk a little to save a little, risk nothing to save nothing' doctrine. This framework guides commanders in calibrating risk levels based on what can be gained.\"\n\nQ: 이 원칙이 지휘관에게 제공하는 것은?","opts":["엄격한 절차","상황별 위험 조율 기준","새 장비 지침","법적 근거"],"ans":1,"exp":"'guides commanders in calibrating risk levels based on what can be gained'","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'integrates'의 의미는?","opts":["separates","combines into one","evaluates","removes"],"ans":1,"exp":"integrates = 통합하다(combines into one)","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'formalized'의 의미는?","opts":["ignored","made official/structured","challenged","simplified"],"ans":1,"exp":"formalized = 공식화했다(made official)","section":"독해","passage":"EX"},{"q":"\"THINCS identifies eight key NTS domains: situational awareness, decision-making, communication, leadership, teamwork, task management, stress management, and adaptability.\"\n\nQ: THINCS의 NTS 8개 영역이 아닌 것은?","opts":["상황인식","장비 조작","스트레스 관리","적응력"],"ans":1,"exp":"장비 조작(equipment operation)은 NTS가 아닌 기술적 역량","section":"독해","passage":"EX"},{"q":"\"The incident commander is responsible for the overall management of the incident. This includes establishing objectives, ordering resources, and ensuring the safety of all personnel.\"\n\nQ: 사고지휘관의 책임이 아닌 것은?","opts":["목표 수립","자원 요청","전체 관리","개인 소방 장비 점검"],"ans":3,"exp":"개인 장비 점검은 개인 책임, 지휘관 직무 아님","section":"독해","passage":"Y"},{"q":"\"Fire flow is the quantity of water required for fire suppression, expressed in gallons per minute (gpm). It depends on building size, construction type, and fire load.\"\n\nQ: 지문에서 'fire flow'에 영향을 주는 요소가 아닌 것은?","opts":["건물 크기","건물 구조 유형","화재 부하","기상 조건"],"ans":3,"exp":"기상 조건은 fire flow 결정 요소로 언급되지 않음","section":"독해","passage":"Y"},{"q":"Q: 지문에서 'suppression'의 의미는?","opts":["ignition","extinguishment/control","spread","detection"],"ans":1,"exp":"fire suppression = 화재 진압·통제(extinguishment/control)","section":"독해","passage":"Y"}]},{"round":5,"title":"제5회 기출 유형","analysis":{"summary":"전 유형 통합 실전. 문법 26문항(고난도 혼합), 청취 80문항 전 파트 완성형, 독해 ICS·NTS·건물구조·안전 종합 지문 3세트.","tips":["시험 전략: 문법 20분 → 청취 30분 → 독해 40분","독해 어휘 문제: 앞뒤 문맥에서 의미 추론","청취: 부정(but/however) 이후 내용이 핵심 정보"]},"qs":[{"type":"현재완료","q":"The unit _____ on standby since 0600.","opts":["is","was","has been","had been"],"ans":2,"exp":"since+시점 → 현재완료(has been)","section":"문법"},{"type":"과거완료","q":"The evacuation _____ completed before the structure collapsed.","opts":["is","was","has been","had been"],"ans":3,"exp":"before+과거(collapsed) → 과거완료 수동(had been p.p.)","section":"문법"},{"type":"가정법 과거","q":"If the equipment _____ in better condition, the task would be easier.","opts":["is","was","were","has been"],"ans":2,"exp":"가정법 과거: If+were → 현재 사실 반대","section":"문법"},{"type":"가정법 과거완료","q":"If the team _____ the warning, the firefighter would not have been injured.","opts":["heeded","heeds","had heeded","has heeded"],"ans":2,"exp":"가정법 과거완료: If+had p.p., would have p.p.","section":"문법"},{"type":"준동사-동명사","q":"The chief recommended _____ all rooftop access points before committing crews.","opts":["to assess","assess","assessing","assessed"],"ans":2,"exp":"recommend+동명사(V-ing)","section":"문법"},{"type":"준동사-to부정사","q":"The department agreed _____ the new accountability system by January.","opts":["implement","implementing","to implement","implemented"],"ans":2,"exp":"agree+to부정사","section":"문법"},{"type":"관계사-who","q":"The medic _____ treated the burn victims received a commendation.","opts":["who","which","whose","whom"],"ans":0,"exp":"사람 선행사+주어 역할 → who","section":"문법"},{"type":"관계사-whose","q":"The officer _____ unit responded first was praised for the fastest deployment.","opts":["who","which","whose","whom"],"ans":2,"exp":"소유 관계 → whose","section":"문법"},{"type":"조동사-must","q":"The radio must _____ malfunctioned — no transmissions were received.","opts":["have","had","be","has"],"ans":0,"exp":"must have p.p. = 과거 강한 추측","section":"문법"},{"type":"조동사-should","q":"The crew should _____ performed a 360-degree walkthrough before entry.","opts":["have","had","be","has"],"ans":0,"exp":"should have p.p. = 했어야 했는데(유감)","section":"문법"},{"type":"수동태","q":"The incident report _____ finalized before the press briefing.","opts":["was","is","has","had"],"ans":0,"exp":"과거 수동태: was+p.p.","section":"문법"},{"type":"미래완료","q":"By next Tuesday, the department _____ its centennial celebrations.","opts":["completes","completed","will complete","will have completed"],"ans":3,"exp":"by+미래시점 → 미래완료(will have p.p.)","section":"문법"},{"type":"가정법-wish","q":"I wish the department _____ adopted the new protocol earlier.","opts":["has","had","would have","will have"],"ans":1,"exp":"wish+가정법 과거완료: wish+주어+had p.p. → 과거 사실 반대","section":"문법"},{"type":"가정법-wish","q":"The firefighter wishes she _____ more time to practice the drill.","opts":["has","had","would have","will have"],"ans":1,"exp":"wish+가정법 과거: wish+주어+had → 현재 사실 반대","section":"문법"},{"type":"복합 시제","q":"By the time you read this report, the investigation _____ for a week.","opts":["will run","will be running","will have been running","runs"],"ans":2,"exp":"by the time+현재 → 미래완료진행(will have been V-ing)","section":"문법"},{"type":"관계부사","q":"The protocol explains the reason _____ all aerial operations were suspended.","opts":["which","that","why","for which"],"ans":2,"exp":"reason+why = 이유 관계부사(= for which)","section":"문법"},{"type":"강조구문","q":"It was the outdated equipment _____ caused the malfunction.","opts":["which","that","who","what"],"ans":1,"exp":"강조구문(It is ... that): It was X that Y → that 고정","section":"문법"},{"type":"복합 관계사","q":"The commander approved _____ the safety officer recommended.","opts":["that","which","what","who"],"ans":2,"exp":"선행사 없는 명사절 목적어 → what(~하는 것을)","section":"문법"},{"type":"도치","q":"Not until the building was secured _____ allowed to enter.","opts":["the crew was","was the crew","the crew is","is the crew"],"ans":1,"exp":"부정어(Not until) 문두 → 주어·동사 도치","section":"문법"},{"type":"준동사-지각동사","q":"The supervisor heard the team _____ the evacuation alarm.","opts":["to activate","activating","activated","activation"],"ans":1,"exp":"지각동사(hear)+목적어+V-ing(진행 중인 동작)","section":"문법"},{"type":"준동사-사역동사","q":"The chief had the recruits _____ the drill twice.","opts":["repeat","to repeat","repeating","repeated"],"ans":0,"exp":"사역동사(have)+목적어+동사원형","section":"문법"},{"type":"간접의문문","q":"Could you tell me _____ the drill starts?","opts":["when does","when","what time does","that when"],"ans":1,"exp":"간접의문문: 의문사+주어+동사(정상 어순)","section":"문법"},{"type":"도치","q":"Only then _____ the true extent of the damage.","opts":["they realized","did they realize","they did realize","realized they"],"ans":1,"exp":"Only+부사 문두 → 조동사+주어 도치","section":"문법"},{"type":"부정사 구문","q":"The regulation requires all units _____ before entering IDLH environments.","opts":["check","checking","to check","checked"],"ans":2,"exp":"require+목적어+to부정사: requires A to V","section":"문법"},{"type":"분사구문","q":"_____ all exits, the safety team confirmed the building was clear.","opts":["Checking","Having checked","To check","Checked"],"ans":1,"exp":"분사구문: Having p.p. = 주절보다 이전에 완료된 동작","section":"문법"},{"type":"간접의문문","q":"The chief asked _____ the new recruits had passed their fitness test.","opts":["that whether","if","whether that","that"],"ans":1,"exp":"간접의문문: asked if/whether+주어+동사","section":"문법"},{"part":1,"q":"[Part 1] \"Has the gas been shut off?\"\n\"The utility company confirmed it was isolated at 0312.\"\n\nQ: 가스 차단 시간은?","opts":["0212","0312","0412","0512"],"ans":1,"exp":"'isolated at 0312'","section":"청취"},{"part":1,"q":"[Part 1] \"How many civilians were displaced by the fire?\"\n\"Forty-three. The Red Cross has set up a shelter at the community center.\"\n\nQ: 이재민 수용 장소는?","opts":["학교","소방서","지역 센터","호텔"],"ans":2,"exp":"'Red Cross ... shelter at the community center'","section":"청취"},{"part":1,"q":"[Part 1] \"Are there any exposures we need to protect?\"\n\"The east wall is about fifteen feet from an occupied residential building.\"\n\nQ: 노출 위험 건물의 위치는?","opts":["서쪽 15피트","동쪽 15피트","북쪽 20피트","남쪽 10피트"],"ans":1,"exp":"'east wall ... fifteen feet from residential building'","section":"청취"},{"part":1,"q":"[Part 1] \"Did the building owner provide access to the utility room?\"\n\"Eventually — took about twenty minutes of negotiation.\"\n\nQ: 다용도실 접근은?","opts":["즉시 허용","약 20분 협상 후 허용","거부됨","경찰이 강제 진입"],"ans":1,"exp":"'took about twenty minutes of negotiation'","section":"청취"},{"part":1,"q":"[Part 1] \"Did all personnel make it out of the collapse zone?\"\n\"All accounted for — PAR was clear.\"\n\nQ: 붕괴 구역 인원 현황은?","opts":["1명 행방불명","전원 확인 완료","2명 부상","PAR 미실시"],"ans":1,"exp":"'All accounted for — PAR was clear'","section":"청취"},{"part":1,"q":"[Part 1] \"Is the water supply adequate for a prolonged operation?\"\n\"We've got two hydrants on Oak and Main — should be sufficient.\"\n\nQ: 사용 가능한 소화전 수는?","opts":["1개","2개","3개","4개"],"ans":1,"exp":"'two hydrants on Oak and Main'","section":"청취"},{"part":1,"q":"[Part 1] \"Is the incident commander still on scene?\"\n\"He handed off to Battalion Chief Park about an hour ago.\"\n\nQ: 현재 사고지휘관은?","opts":["원래 지휘관","Park 대대장","부서장","훈련 지휘관"],"ans":1,"exp":"'handed off to Battalion Chief Park'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The thermal camera flagged a hot spot on the east wall during overhaul.\"\n\"Did the crew investigate it?\"\n\"Yes — they opened up about four feet of wall and found smoldering insulation. It was extinguished, but it could have rekindled overnight.\"\n\nQ: 동쪽 벽에서 발견된 것은?","opts":["가스관 손상","훈소하는 단열재","전기 화재 흔적","구조적 손상"],"ans":1,"exp":"'smoldering insulation'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"What's the main takeaway from this incident?\"\n\"Coordination between ventilation and attack teams needs to be tighter. We'll add that to the drill curriculum.\"\n\nQ: 주요 개선 사항은?","opts":["RIT 배치 변경","환기-진압 팀 조율 강화","진입 시점 교정","MAYDAY 절차 수정"],"ans":1,"exp":"'Coordination between ventilation and attack teams needs to be tighter'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The post-incident analysis showed three critical decision points where the outcome could have been different.\"\n\"Which ones?\"\n\"Entry timing, ventilation coordination, and RIT positioning. If any one of those had gone differently, we might have had a mayday.\"\n\nQ: 분석에서 밝혀진 결정적 실수 수는?","opts":["1가지","2가지","3가지","4가지"],"ans":2,"exp":"'three critical decision points'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (1/2)]\n\n\"The community is demanding a public explanation for the response delay.\"\n\"I understand. We need to be transparent. Let's schedule a press conference and walk them through the timeline.\"\n\"Should we involve legal counsel?\"\n\"Yes — standard procedure for any incident that draws this level of scrutiny.\"\n\nQ: 대응 지연에 대한 결정된 조치는?","opts":["언론 보도 차단","법적 대응 거부","기자회견 개최 및 타임라인 공개","관계자 즉시 징계"],"ans":2,"exp":"'schedule a press conference and walk them through the timeline'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"Good catch. Make sure overhaul protocols include mandatory thermal imaging of adjacent walls going forward.\"\n\"Already drafting the SOG update. I'll have it ready by next shift.\"\n\nQ: SOG 업데이트 완료 예정 시점은?","opts":["오늘 중","다음 교대 전","다음 주","한 달 이내"],"ans":1,"exp":"'ready by next shift'","section":"청취"},{"part":2,"q":"[Part 2 — 긴 대화 (2/2)]\n\n\"When should we hold the press conference?\"\n\"Let's aim for Thursday — that gives us two days to compile the full timeline and coordinate with the mayor's office.\"\n\nQ: 기자회견 예정일은?","opts":["화요일","수요일","목요일","금요일"],"ans":2,"exp":"'aim for Thursday'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Following last month's near-miss incident, all engine companies will participate in a mandatory hose load refresher. The training will be conducted in three sessions this week: Tuesday, Wednesday, and Friday. All company officers must sign attendance sheets and submit them to training by end of day Friday.\"\n\nQ: 출석 명단 제출 마감은?","opts":["화요일 종례","수요일 종례","금요일 종례","다음 주 월요일"],"ans":2,"exp":"'submit them to training by end of day Friday'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"The department will be conducting a multi-agency disaster drill on the 18th. Participating agencies include fire, EMS, law enforcement, and public works. All personnel should be in uniform and report to the staging area at 0700. Observers from city hall will be present, so professionalism is expected.\"\n\nQ: 훈련에 참여하지 않는 기관은?","opts":["소방","의료","법 집행","공중 보건"],"ans":3,"exp":"public works(공공 작업)가 있지만 공중 보건(public health)은 언급되지 않음","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"A reminder that all annual SCBA fit tests must be completed before the end of the quarter. If you have not yet scheduled yours, contact the equipment coordinator immediately. Personnel who fail to complete the test will be placed on restricted duty until compliance is achieved.\"\n\nQ: 적합성 시험 미완료 시 결과는?","opts":["급여 삭감","징계 처분","제한 근무 배치","즉시 휴직"],"ans":2,"exp":"'placed on restricted duty until compliance is achieved'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Tonight's scene involves a suspected natural gas leak in a residential neighborhood. Evacuate a two-block radius. No motorized vehicles, open flames, or electrical operation within that zone. Once the utility company confirms isolation, ventilate the affected structures before allowing any re-entry.\"\n\nQ: 가스 차단 확인 후 재진입 전 해야 할 것은?","opts":["구조물 사진 촬영","인근 건물 수색","영향받은 구조물 환기","전기 공급 복구"],"ans":2,"exp":"'ventilate the affected structures before allowing any re-entry'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"The new Personnel Accountability System goes live on the first of next month. Every firefighter will be issued a new accountability tag embedded with an RFID chip. These replace the old dog-tag system. Failure to carry your tag while on duty will result in a written warning on first offense, and suspension on the second.\"\n\nQ: 태그 미소지 시 두 번째 위반 처벌은?","opts":["구두 경고","서면 경고","정직","해임"],"ans":2,"exp":"'suspension on the second'","section":"청취"},{"part":3,"q":"[Part 3 — 담화]\n\n\"Effective immediately, all incident commanders must submit a written size-up report within 30 minutes of arrival at any working structure fire. The report must include: life safety status, fire conditions, building construction type, and resource needs. Forms are available in the command vehicle.\"\n\nQ: 30분 이내 보고서에 포함해야 할 항목이 아닌 것은?","opts":["인명 안전 현황","화재 조건","건물 구조 유형","화재 원인 추정"],"ans":3,"exp":"화재 원인 추정은 언급된 4개 항목에 없음","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"Klein's research found that experienced firefighters rarely compare multiple options. Instead, they mentally simulate the chosen course of action to check for obvious flaws, then act. This mental simulation — 'if I do this, what happens?' — is a key feature of expert decision-making.\"\n\nQ: 숙련된 소방관의 의사결정에서 '정신적 시뮬레이션'의 역할은?","opts":["선택지 수를 늘림","선택된 행동 과정의 명백한 결함 확인","팀 전체에 결정 전달","문서 작성"],"ans":1,"exp":"'mentally simulate ... to check for obvious flaws'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Decision-making under stress follows two primary models: the classical analytical model, which evaluates multiple options systematically, and the Recognition-Primed Decision (RPD) model, developed by Gary Klein. RPD describes how experienced decision-makers use pattern recognition to rapidly identify a workable solution without comparing alternatives.\"\n\nQ: RPD 모델의 핵심 특징은?","opts":["모든 선택지 체계적 분석","패턴 인식으로 빠르게 실행 가능한 해결책 식별","팀 합의를 통한 결정","데이터 기반 의사결정"],"ans":1,"exp":"'pattern recognition to rapidly identify a workable solution without comparing alternatives'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"Type III construction — ordinary construction — combines non-combustible exterior walls with combustible interior framing. The void spaces within these walls allow fire to travel vertically unseen, a phenomenon known as balloon frame fire spread.\"\n\nQ: Type III 건물에서 화재가 눈에 보이지 않게 수직으로 확산하는 이유는?","opts":["알루미늄 외벽","벽 내 빈 공간","스프링클러 부재","목재 바닥"],"ans":1,"exp":"'void spaces within these walls allow fire to travel vertically unseen'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Accountability at the fireground operates on three levels: individual accountability, where each firefighter knows their assignment; company accountability, where officers track their crew; and command accountability, where IC maintains situational awareness of all resources.\"\n\nQ: 지휘 책임(command accountability)의 핵심은?","opts":["개인 임무 파악","팀 추적","IC의 전체 자원 상황인식 유지","문서 작성"],"ans":2,"exp":"'IC maintains situational awareness of all resources'","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"Today we examine building construction types and their fire behavior implications. Type I — fire resistive — uses non-combustible materials and typically withstands fire longest. Type V — wood frame — is the most common in residential construction and presents the greatest collapse risk due to rapid heat damage to structural members.\"\n\nQ: 화재 시 붕괴 위험이 가장 높은 건물 유형은?","opts":["Type I (내화)","Type II (비연소)","Type IV (중목재)","Type V (목조)"],"ans":3,"exp":"'Type V — wood frame ... greatest collapse risk'","section":"청취"},{"part":4,"q":"[Part 4 — 강의 계속]\n\n\"A Personnel Accountability Report (PAR) is a roll call of all assigned personnel at defined intervals or triggered by significant events — a MAYDAY, sudden change in fire conditions, or transition from offensive to defensive operations.\"\n\nQ: PAR 실시를 트리거하는 사건이 아닌 것은?","opts":["MAYDAY 발령","화재 상황 급변","공세→수세 전환","정기 교대 시간"],"ans":3,"exp":"정기 교대 시간은 PAR 트리거로 언급되지 않음","section":"청취"},{"part":4,"q":"[Part 4 — 강의]\n\n\"The Phoenix Model of risk management — developed by the Phoenix Fire Department — states: risk a lot to save a savable life, risk a little to save savable property, and risk nothing to save what is already lost. This model has been widely adopted internationally.\"\n\nQ: Phoenix 모델에서 '이미 잃은 것을 구하기 위해' 감수해야 할 위험은?","opts":["최대한","약간","없음","상황에 따라"],"ans":2,"exp":"'risk nothing to save what is already lost'","section":"청취"},{"q":"Q: 지문에서 'occupancy loads'의 의미는?","opts":["weight limits","number of people in a building","utility capacity","fire load"],"ans":1,"exp":"occupancy load = 건물 재실 인원 수","section":"독해","passage":"X"},{"q":"\"Incident size-up is a continuous process that begins before arrival and continues throughout the incident. Key factors include: building construction, occupancy, life safety, fire extension, and available resources.\"\n\nQ: 상황평가(size-up)는 언제 시작하는가?","opts":["현장 도착 후","내부 진입 후","도착 전부터 지속적으로","지휘소 설치 후"],"ans":2,"exp":"'begins before arrival and continues throughout'","section":"독해","passage":"X"},{"q":"\"Overhaul is the systematic process of searching the fire scene for hidden hot spots after the main fire is controlled. Thermal imaging cameras significantly enhance overhaul efficiency.\"\n\nQ: 잔화처리 중 열화상 카메라의 역할은?","opts":["화재 원인 조사","숨겨진 열점 탐지 효율 향상","통신 지원","건물 구조 분석"],"ans":1,"exp":"'Thermal imaging cameras significantly enhance overhaul efficiency'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'systematic'의 의미는?","opts":["random","methodical/organized","rapid","minimal"],"ans":1,"exp":"systematic = 체계적인(methodical/organized)","section":"독해","passage":"X"},{"q":"Q: 지문에서 'salvage'의 의미는?","opts":["destruction","property protection after disaster","fire suppression","evacuation"],"ans":1,"exp":"salvage = 화재 후 재산 보호 작업","section":"독해","passage":"X"},{"q":"\"Firefighter fatalities from cardiac events account for nearly 45% of line-of-duty deaths annually. Regular cardiovascular fitness assessments and mandatory medical evaluations are now standard in most departments.\"\n\nQ: 심장 관련 사망이 전체의 몇 퍼센트를 차지하는가?","opts":["약 25%","약 35%","약 45%","약 55%"],"ans":2,"exp":"'nearly 45% of line-of-duty deaths'","section":"독해","passage":"X"},{"q":"\"Preplanning visits allow fire crews to familiarize themselves with building layouts, hazards, utility shutoffs, and occupancy loads. Buildings with completed preplans consistently show better outcomes during actual incidents.\"\n\nQ: 사전 계획 방문의 이점은?","opts":["건물 소유자와 관계 형성","대응 효과 향상","법적 면책","건물 코드 검사"],"ans":1,"exp":"'better outcomes during actual incidents'","section":"독해","passage":"X"},{"q":"Q: 지문에서 'congestion'의 의미는?","opts":["danger","overcrowding/blockage","noise","delay"],"ans":1,"exp":"congestion = 혼잡, 밀집(overcrowding)","section":"독해","passage":"X"},{"q":"\"Ground monitors — large-caliber nozzles positioned without requiring a firefighter to hold them — are used in defensive operations to deliver high-volume streams.\"\n\nQ: 지상 모니터의 주요 장점은?","opts":["높은 정밀도","소방관 없이 고용량 방수 가능","실내 전용","이동성"],"ans":1,"exp":"'without requiring a firefighter to hold them'","section":"독해","passage":"X"},{"q":"\"Mayday procedures require: announcing MAYDAY three times, stating name and unit, describing the emergency, and providing location. The IC assigns a dedicated channel and activates the RIT.\"\n\nQ: MAYDAY 선언 시 가장 먼저 해야 하는 것은?","opts":["위치 알리기","MAYDAY 세 번 반복","RIT 가동","채널 변경"],"ans":1,"exp":"'announcing MAYDAY three times' → 가장 먼저 세 번 반복","section":"독해","passage":"X"},{"q":"\"Unified command is appropriate when an incident involves multiple jurisdictions or agencies with overlapping responsibilities. Each agency retains its own authority while contributing to a single Incident Action Plan.\"\n\nQ: 통합지휘가 적합한 상황은?","opts":["단일 기관 소규모 사고","다관할·다기관 중복 책임 사고","야간 단독 사고","훈련 중"],"ans":1,"exp":"'multiple jurisdictions or agencies with overlapping responsibilities'","section":"독해","passage":"X"},{"q":"\"Conflagrations — large fires that spread beyond their point of origin to involve multiple structures — require regional mutual aid and can overwhelm local resources. Historic conflagrations often reshape building codes and fire prevention strategies.\"\n\nQ: 대규모 화재(conflagration)의 장기적 영향은?","opts":["일시적 혼란","건축 법규·방화 전략 재편","보험 비용 감소","지역 경제 성장"],"ans":1,"exp":"'reshape building codes and fire prevention strategies'","section":"독해","passage":"X"},{"q":"\"The incident action plan (IAP) is updated each operational period to reflect changing conditions. It documents objectives, strategies, tactics, and resource assignments.\"\n\nQ: IAP가 업데이트되는 시점은?","opts":["사고 시작 시 한 번","매 작전 기간마다","48시간마다","사고 종료 후"],"ans":1,"exp":"'updated each operational period'","section":"독해","passage":"X"},{"q":"\"The staging area is a designated location where resources are assembled and await assignment. It is separate from the operational area to reduce congestion and improve coordination.\"\n\nQ: 대기 구역(staging area)이 작전 구역과 분리되는 이유는?","opts":["보안 유지","혼잡 감소 및 조율 향상","비용 절감","법적 요건"],"ans":1,"exp":"'reduce congestion and improve coordination'","section":"독해","passage":"X"},{"q":"\"Salvage operations protect property from water, smoke, and overhaul damage after the main fire is controlled. Covers, mops, and squeegees are essential salvage tools.\"\n\nQ: 잔화처리(salvage) 작업의 주요 목적은?","opts":["잔불 제거","수색 실시","추가 피해로부터 재산 보호","화재 원인 조사"],"ans":2,"exp":"'protect property from water, smoke, and overhaul damage'","section":"독해","passage":"X"},{"q":"\"Breathing air cylinders for SCBA must be hydrostatically tested every five years. Any cylinder showing corrosion, dents, or damage to the neck threads must be removed from service immediately.\"\n\nQ: SCBA 실린더를 즉시 사용 중단해야 하는 조건은?","opts":["5년 미경과","사용 횟수 초과","부식·움푹 팬 곳·목 나사산 손상","압력 약간 감소"],"ans":2,"exp":"'corrosion, dents, or damage to the neck threads'","section":"독해","passage":"X"},{"q":"\"Water curtains can be used to protect exposures from radiant heat during large fires. They create a water barrier between the burning structure and adjacent buildings.\"\n\nQ: 수막(water curtain)의 용도는?","opts":["화재 직접 진압","복사열로부터 인접 건물 보호","시야 확보","연기 제거"],"ans":1,"exp":"'protect exposures from radiant heat'","section":"독해","passage":"X"},{"q":"\"THINCS identifies eight key NTS domains: situational awareness, decision-making, communication, leadership, teamwork, task management, stress management, and adaptability.\"\n\nQ: THINCS의 NTS 8개 영역이 아닌 것은?","opts":["상황인식","장비 조작","스트레스 관리","적응력"],"ans":1,"exp":"장비 조작(equipment operation)은 NTS가 아닌 기술적 역량","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'pioneered'의 의미는?","opts":["criticized","followed","developed/led the way","rejected"],"ans":2,"exp":"pioneered = 선구적으로 개척했다","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'integrates'의 의미는?","opts":["separates","combines into one","evaluates","removes"],"ans":1,"exp":"integrates = 통합하다(combines into one)","section":"독해","passage":"EX"},{"q":"\"Risk a nothing to save nothing' applies when there is no potential for life safety — for example, when a structure is fully involved and confirmed unoccupied. In such cases, defensive operations protect firefighters.\"\n\nQ: '아무것도 걸지 않는다' 원칙을 적용하는 상황은?","opts":["생존자 확인 시","구조물이 완전 연소되고 비어있음이 확인된 때","소형 화재","야간 작전"],"ans":1,"exp":"'when structure is fully involved and confirmed unoccupied'","section":"독해","passage":"EX"},{"q":"\"FIRESCOPE (Firefighting Resources of Southern California Organized for Potential Emergencies) was the collaborative effort that formalized ICS. It emerged from lessons learned during the 1970 Laguna and Claremont fires.\"\n\nQ: FIRESCOPE의 기원이 된 사건은?","opts":["1980년대 허리케인","1970년 Laguna·Claremont 산불","9/11 테러","1990년대 홍수"],"ans":1,"exp":"'emerged from lessons learned during the 1970 Laguna and Claremont fires'","section":"독해","passage":"EX"},{"q":"\"FIRESCOPE established common terminology, unified command, and modular organization — concepts that became the foundation of ICS and later NIMS.\"\n\nQ: FIRESCOPE가 확립한 개념이 아닌 것은?","opts":["공통 용어","통합 지휘","모듈 조직","드론 운용"],"ans":3,"exp":"드론 운용은 FIRESCOPE 당시(1970년대) 개념이 아님","section":"독해","passage":"EX"},{"q":"\"The UK THINCS model (Tactical, Human, Incident, Non-technical Command Skills) integrates technical and non-technical competencies into a single framework for evaluating incident commanders.\"\n\nQ: THINCS 모델의 특징은?","opts":["기술 역량만 평가","기술·비기술 역량 통합 평가","인원 관리 전용","장비 평가 도구"],"ans":1,"exp":"'integrates technical and non-technical competencies'","section":"독해","passage":"EX"},{"q":"Q: 지문에서 'formalized'의 의미는?","opts":["ignored","made official/structured","challenged","simplified"],"ans":1,"exp":"formalized = 공식화했다(made official)","section":"독해","passage":"EX"},{"q":"\"The incident commander is responsible for the overall management of the incident. This includes establishing objectives, ordering resources, and ensuring the safety of all personnel.\"\n\nQ: 사고지휘관의 책임이 아닌 것은?","opts":["목표 수립","자원 요청","전체 관리","개인 소방 장비 점검"],"ans":3,"exp":"개인 장비 점검은 개인 책임, 지휘관 직무 아님","section":"독해","passage":"Y"},{"q":"\"Fire flow is the quantity of water required for fire suppression, expressed in gallons per minute (gpm). It depends on building size, construction type, and fire load.\"\n\nQ: 지문에서 'fire flow'에 영향을 주는 요소가 아닌 것은?","opts":["건물 크기","건물 구조 유형","화재 부하","기상 조건"],"ans":3,"exp":"기상 조건은 fire flow 결정 요소로 언급되지 않음","section":"독해","passage":"Y"},{"q":"Q: 지문에서 'suppression'의 의미는?","opts":["ignition","extinguishment/control","spread","detection"],"ans":1,"exp":"fire suppression = 화재 진압·통제(extinguishment/control)","section":"독해","passage":"Y"}]}];
